import { streamText, convertToModelMessages } from "ai";
import { auth } from "@/auth";
import { getModel } from "@/lib/ai/providers";
import { getSystemPrompt } from "@/lib/ai/system-prompts";
import { checkRateLimit } from "@/lib/ai/rate-limit";
import { resolveProviderModel } from "@/lib/ai/resolve-provider-model";
import { aiCompletionSchema } from "@/lib/ai/schemas";
import { readJsonBody, ReadJsonBodyError } from "@/lib/api/read-json-body";
import { db } from "@/lib/db";
import { users } from "@/lib/db/schema";
import { eq } from "drizzle-orm";

export const maxDuration = 30;
const MAX_COMPLETE_BODY_BYTES = 300_000;

export async function POST(req: Request) {
  const session = await auth();
  if (!session?.user?.id) {
    return Response.json({ error: "Unauthorized" }, { status: 401 });
  }

  let body: unknown;
  try {
    body = await readJsonBody(req, MAX_COMPLETE_BODY_BYTES);
  } catch (error) {
    if (error instanceof ReadJsonBodyError) {
      return Response.json({ error: error.message }, { status: error.status });
    }
    throw error;
  }

  // Validate request body with Zod
  const parsed = aiCompletionSchema.safeParse(body);
  if (!parsed.success) {
    return Response.json(
      { error: "Invalid request", issues: parsed.error.issues },
      { status: 400 }
    );
  }

  const { messages, prompt, context, selectedText, mode } = parsed.data;
  const needsUserPrefs = !parsed.data.provider || !parsed.data.model;
  let userRow:
    | { aiProvider: string | null; aiModel: string | null }
    | undefined;

  if (needsUserPrefs) {
    [userRow] = await db
      .select({ aiProvider: users.aiProvider, aiModel: users.aiModel })
      .from(users)
      .where(eq(users.id, session.user.id));
  }

  const providerModel = resolveProviderModel({
    requestedProvider: parsed.data.provider,
    requestedModel: parsed.data.model,
    storedProvider: userRow?.aiProvider,
    storedModel: userRow?.aiModel,
  });

  if (providerModel.invalidRequestedModel) {
    return Response.json({ error: "Invalid model for provider" }, { status: 400 });
  }
  const { provider, model } = providerModel;

  // Rate limit check (database-backed, serverless-safe)
  const { allowed } = await checkRateLimit(session.user.id);
  if (!allowed) {
    return Response.json(
      { error: "Rate limit exceeded. Max 20 requests per minute." },
      { status: 429 }
    );
  }

  const systemPrompt = getSystemPrompt(mode);
  const aiModel = getModel(provider, model);

  try {
    // Build streamText options based on input type
    if (messages) {
      // Inject document context into system prompt for Side Panel mode
      let system = systemPrompt;
      if (context) {
        system = `${systemPrompt}\n\nDocument context:\n${context}`;
      }

      const result = streamText({
        model: aiModel,
        system,
        messages: await convertToModelMessages(
          messages as Parameters<typeof convertToModelMessages>[0]
        ),
      });

      return result.toUIMessageStreamResponse({
        messageMetadata: ({
          part,
        }: {
          part: { type: string; finishReason?: string };
        }) => {
          if (
            part.type === "finish" &&
            part.finishReason === "content-filter"
          ) {
            return {
              blocked: true,
              reason: "Content filtered by AI provider",
            };
          }
        },
      });
    }

    // Single prompt mode (inline/freeform)
    let fullPrompt = prompt!;
    if (selectedText) {
      fullPrompt = `Selected text: "${selectedText}"\n\nInstruction: ${prompt}`;
    }
    if (context) {
      fullPrompt = `Document context:\n${context}\n\n${fullPrompt}`;
    }

    const result = streamText({
      model: aiModel,
      system: systemPrompt,
      prompt: fullPrompt,
    });

    return result.toUIMessageStreamResponse({
      messageMetadata: ({
        part,
      }: {
        part: { type: string; finishReason?: string };
      }) => {
        if (
          part.type === "finish" &&
          part.finishReason === "content-filter"
        ) {
          return {
            blocked: true,
            reason: "Content filtered by AI provider",
          };
        }
      },
    });
  } catch (error) {
    console.error("[AI Complete] Error:", error);
    return Response.json(
      { error: error instanceof Error ? error.message : "Internal server error" },
      { status: 500 }
    );
  }
}

import { streamText, smoothStream, convertToModelMessages } from "ai";
import { auth } from "@/auth";
import { getModel } from "@/lib/ai/providers";
import { getSystemPrompt } from "@/lib/ai/system-prompts";
import { checkRateLimit } from "@/lib/ai/rate-limit";
import { resolveProviderModel } from "@/lib/ai/resolve-provider-model";
import { chatRequestSchema } from "@/lib/ai/schemas";
import { readJsonBody, ReadJsonBodyError } from "@/lib/api/read-json-body";
import { db } from "@/lib/db";
import { users } from "@/lib/db/schema";
import { eq } from "drizzle-orm";

export const maxDuration = 60;
const MAX_CHAT_BODY_BYTES = 400_000;

export async function POST(req: Request) {
  const session = await auth();
  if (!session?.user?.id) {
    return Response.json({ error: "Unauthorized" }, { status: 401 });
  }

  let body: unknown;
  try {
    body = await readJsonBody(req, MAX_CHAT_BODY_BYTES);
  } catch (error) {
    if (error instanceof ReadJsonBodyError) {
      return Response.json({ error: error.message }, { status: error.status });
    }
    throw error;
  }

  const parsed = chatRequestSchema.safeParse(body);
  if (!parsed.success) {
    return Response.json(
      { error: "Invalid request", issues: parsed.error.issues },
      { status: 400 }
    );
  }

  const { messages, documentContext } = parsed.data;
  const needsUserPrefs = !parsed.data.provider || !parsed.data.model;
  let userRow:
    | { aiProvider: string | null; aiModel: string | null }
    | undefined;

  if (needsUserPrefs) {
    [userRow] = await db
      .select({ aiProvider: users.aiProvider, aiModel: users.aiModel })
      .from(users)
      .where(eq(users.id, session.user.id));
  }

  const providerModel = resolveProviderModel({
    requestedProvider: parsed.data.provider,
    requestedModel: parsed.data.model,
    storedProvider: userRow?.aiProvider,
    storedModel: userRow?.aiModel,
  });

  if (providerModel.invalidRequestedModel) {
    return Response.json(
      { error: "Invalid model for provider" },
      { status: 400 }
    );
  }
  const { provider, model } = providerModel;

  const { allowed } = await checkRateLimit(session.user.id);
  if (!allowed) {
    return Response.json(
      { error: "Rate limit exceeded. Max 20 requests per minute." },
      { status: 429 }
    );
  }

  let system = getSystemPrompt("chat");
  if (documentContext) {
    system += "\n\n---\nWriter's document:\n" + documentContext + "\n---";
  }

  const aiModel = getModel(provider, model);

  try {
    const result = streamText({
      model: aiModel,
      system,
      messages: await convertToModelMessages(
        messages as Parameters<typeof convertToModelMessages>[0]
      ),
      experimental_transform: smoothStream({ chunking: "word" }),
    });

    return result.toUIMessageStreamResponse({
      sendReasoning: false,
      messageMetadata: ({
        part,
      }: {
        part: { type: string; finishReason?: string; usage?: { totalTokens?: number } };
      }) => {
        if (part.type === "finish") {
          return {
            provider,
            model,
            blocked: part.finishReason === "content-filter",
            ...(part.usage ? { tokenCount: part.usage.totalTokens } : {}),
          };
        }
      },
    });
  } catch (error) {
    console.error("[Chat] Error:", error);
    return Response.json(
      {
        error:
          error instanceof Error ? error.message : "Internal server error",
      },
      { status: 500 }
    );
  }
}

import { auth } from "@/auth";
import { db } from "@/lib/db";
import { documents, badges } from "@/lib/db/schema";
import { eq, desc, sql } from "drizzle-orm";
import { redirect } from "next/navigation";
import { createDocument } from "@/app/actions/documents";
import { DashboardContent } from "@/components/dashboard/DashboardContent";

export default async function DashboardPage() {
  const session = await auth();

  if (!session?.user?.id) {
    redirect("/login");
  }

  const userDocuments = await db
    .select()
    .from(documents)
    .where(eq(documents.userId, session.user.id))
    .orderBy(desc(documents.updatedAt));

  // Fetch badge stats (ai_percentage) per document
  const badgeStatsMap = new Map<
    string,
    { count: number; aiPercentage: number | null; latestVerificationId: string | null }
  >();
  const docIds = userDocuments.map((d) => d.id);
  if (docIds.length > 0) {
    const badgeRows = await db
      .select({
        documentId: badges.documentId,
        count: sql<number>`count(*)::int`,
        latestStats: sql<string>`(array_agg(${badges.stats} ORDER BY ${badges.createdAt} DESC))[1]::text`,
        latestVerificationId: sql<string>`(array_agg(${badges.verificationId} ORDER BY ${badges.createdAt} DESC))[1]::text`,
      })
      .from(badges)
      .where(
        sql`${badges.documentId} IN (${sql.join(
          docIds.map((id) => sql`${id}`),
          sql`, `
        )})`
      )
      .groupBy(badges.documentId);

    for (const row of badgeRows) {
      let aiPercentage: number | null = null;
      try {
        const stats = JSON.parse(row.latestStats);
        aiPercentage = stats?.ai_percentage ?? stats?.aiPercentage ?? null;
      } catch { /* ignore parse errors */ }
      badgeStatsMap.set(row.documentId, {
        count: row.count,
        aiPercentage,
        latestVerificationId: row.latestVerificationId ?? null,
      });
    }
  }

  const documentData = userDocuments.map((doc) => {
    const badgeInfo = badgeStatsMap.get(doc.id);
    // Extract preview from content JSON
    let preview = "";
    try {
      const content = doc.content as { content?: Array<{ content?: Array<{ text?: string }> }> };
      const firstParagraph = content?.content?.find((n) => n.content?.some((c) => c.text));
      preview = firstParagraph?.content?.map((c) => c.text ?? "").join("") ?? "";
    } catch { /* ignore */ }

    return {
      id: doc.id,
      title: doc.title,
      updatedAt: doc.updatedAt,
      wordCount: doc.wordCount,
      deletedAt: doc.deletedAt,
      preview: preview.slice(0, 100),
      aiPercentage: badgeInfo?.aiPercentage ?? null,
      badgeCount: badgeInfo?.count ?? 0,
      latestBadgeVerificationId: badgeInfo?.latestVerificationId ?? null,
    };
  });

  const createAction = async () => {
    "use server";
    return createDocument();
  };

  return (
    <DashboardContent
      documents={documentData}
      referenceNowMs={Date.now()}
      createAction={createAction}
    />
  );
}

