"use client";

import { useState, useCallback, useEffect, useRef } from "react";
import { Editor } from "@/components/editor/Editor";
import { useAutoSave } from "@/hooks/useAutoSave";
import { useSession } from "@/hooks/useSession";
import { SaveIndicator } from "@/components/editor/SaveIndicator";
import { BackLink } from "@/components/ui/BackLink";
import { Button } from "@/components/ui/button";
import Link from "next/link";

const PANEL_STATE_VERSION = 1;

interface StoredPanelState {
  version: number;
  chatOpen: boolean;
  editorOpen: boolean;
}

function panelStateKey(documentId: string): string {
  return `provenance:editor:${documentId}:panels`;
}

function readPanelState(documentId: string): Pick<StoredPanelState, "chatOpen" | "editorOpen"> {
  if (typeof window === "undefined") {
    return { chatOpen: true, editorOpen: true };
  }

  try {
    const raw = window.localStorage.getItem(panelStateKey(documentId));
    if (!raw) return { chatOpen: true, editorOpen: true };
    const parsed = JSON.parse(raw) as Partial<StoredPanelState>;
    if (parsed.version !== PANEL_STATE_VERSION) {
      return { chatOpen: true, editorOpen: true };
    }
    const chatOpen = parsed.chatOpen !== false;
    const editorOpen = parsed.editorOpen !== false;
    if (!chatOpen && !editorOpen) {
      return { chatOpen: true, editorOpen: true };
    }
    return { chatOpen, editorOpen };
  } catch {
    return { chatOpen: true, editorOpen: true };
  }
}

interface ThreadSummary {
  id: string;
  title: string;
  messageCount: number | null;
  updatedAt: Date | null;
}

interface EditorShellProps {
  documentId: string;
  initialTitle: string;
  initialContent: Record<string, unknown>;
  aiProvider: string;
  aiModel: string | null;
  latestBadgeVerificationId?: string | null;
  initialChatThreads?: ThreadSummary[];
}

export function EditorShell({
  documentId,
  initialTitle,
  initialContent,
  aiProvider,
  aiModel,
  latestBadgeVerificationId,
  initialChatThreads = [],
}: EditorShellProps) {
  const [title, setTitle] = useState(initialTitle);
  const [chatOpen, setChatOpen] = useState(
    () => readPanelState(documentId).chatOpen
  );
  const [editorOpen, setEditorOpen] = useState(
    () => readPanelState(documentId).editorOpen
  );
  const { save, status, retry, isDirty } = useAutoSave({ documentId, title });
  const { markActive } = useSession({ documentId });
  const isDirtyRef = useRef(isDirty);

  isDirtyRef.current = isDirty;

  const handleUpdate = useCallback(
    (json: Record<string, unknown>) => {
      markActive();
      save(json);
    },
    [save, markActive]
  );

  useEffect(() => {
    const handleClick = (e: MouseEvent) => {
      if (!isDirtyRef.current) return;

      const anchor = (e.target as HTMLElement).closest("a");
      if (!anchor) return;

      const href = anchor.getAttribute("href");
      if (!href || href.startsWith("http") || href.startsWith("#")) return;

      const confirmed = window.confirm(
        "You have unsaved changes. Are you sure you want to leave?"
      );

      if (!confirmed) {
        e.preventDefault();
        e.stopPropagation();
      }
    };

    document.addEventListener("click", handleClick, true);
    return () => document.removeEventListener("click", handleClick, true);
  }, []);

  useEffect(() => {
    if (typeof window === "undefined") return;
    window.localStorage.setItem(
      panelStateKey(documentId),
      JSON.stringify({
        version: PANEL_STATE_VERSION,
        chatOpen,
        editorOpen,
      } satisfies StoredPanelState)
    );
  }, [documentId, chatOpen, editorOpen]);

  return (
    <div className="flex min-h-0 flex-1 flex-col">
      <a href="#editor-content" className="sr-only focus:not-sr-only focus:absolute focus:z-50 focus:rounded-md focus:bg-background focus:px-3 focus:py-2 focus:text-sm focus:shadow-md">
        Skip to editor
      </a>
      <nav className="flex shrink-0 items-center gap-3 border-b border-border px-2 py-1.5" aria-label="Editor navigation">
        <BackLink href="/dashboard" />
        <input
          value={title}
          onChange={(e) => setTitle(e.target.value)}
          aria-label="Document title"
          data-testid="document-title"
          className="flex-1 rounded-md bg-transparent px-1 text-lg font-semibold outline-none placeholder:text-muted-foreground focus-visible:ring-2 focus-visible:ring-ring/50"
          placeholder="Untitled"
        />
        <SaveIndicator status={status} onRetry={retry} />
        {latestBadgeVerificationId && (
          <Button variant="outline" size="sm" asChild>
            <Link href={`/verify/${latestBadgeVerificationId}`}>
              View Badge
            </Link>
          </Button>
        )}
        <Button variant="outline" size="sm" asChild>
          <Link href={`/editor/${documentId}/preview`} data-testid="generate-badge">
            Generate Badge
          </Link>
        </Button>
      </nav>
      <Editor
        content={initialContent}
        documentId={documentId}
        provider={aiProvider}
        model={aiModel ?? undefined}
        onUpdate={handleUpdate}
        chatOpen={chatOpen}
        onChatToggle={() => {
          if (!chatOpen || editorOpen) setChatOpen((v) => !v);
        }}
        editorOpen={editorOpen}
        onEditorToggle={() => {
          if (!editorOpen || chatOpen) setEditorOpen((v) => !v);
        }}
        initialChatThreads={initialChatThreads}
      />
    </div>
  );
}

import { auth } from "@/auth";
import { db } from "@/lib/db";
import { documents, users, chatThreads, badges } from "@/lib/db/schema";
import { eq, and, isNull, desc } from "drizzle-orm";
import { redirect, notFound } from "next/navigation";
import { EditorShell } from "./editor-shell";

export default async function EditorPage({
  params,
}: {
  params: Promise<{ id: string }>;
}) {
  const { id } = await params;
  const session = await auth();

  if (!session?.user?.id) {
    redirect("/login");
  }

  const [document] = await db
    .select()
    .from(documents)
    .where(and(eq(documents.id, id), isNull(documents.deletedAt)));

  if (!document) {
    notFound();
  }

  if (document.userId !== session.user.id) {
    redirect("/dashboard");
  }

  const [prefs, threads, latestBadge] = await Promise.all([
    db
      .select({ aiProvider: users.aiProvider, aiModel: users.aiModel })
      .from(users)
      .where(eq(users.id, session.user.id))
      .then((rows) => rows[0]),
    db
      .select({
        id: chatThreads.id,
        title: chatThreads.title,
        messageCount: chatThreads.messageCount,
        updatedAt: chatThreads.updatedAt,
      })
      .from(chatThreads)
      .where(eq(chatThreads.documentId, id))
      .orderBy(desc(chatThreads.updatedAt)),
    db
      .select({ verificationId: badges.verificationId })
      .from(badges)
      .where(eq(badges.documentId, id))
      .orderBy(desc(badges.createdAt))
      .then((rows) => rows[0]),
  ]);

  return (
    <div className="flex h-screen flex-col px-2 py-1">
      <EditorShell
        documentId={document.id}
        initialTitle={document.title}
        initialContent={document.content as Record<string, unknown>}
        aiProvider={prefs?.aiProvider ?? "anthropic"}
        aiModel={prefs?.aiModel ?? null}
        latestBadgeVerificationId={latestBadge?.verificationId ?? null}
        initialChatThreads={threads}
      />
    </div>
  );
}

import { db } from "@/lib/db";
import { badges } from "@/lib/db/schema";
import { eq } from "drizzle-orm";
import { notFound } from "next/navigation";
import Link from "next/link";
import {
  calculateMetrics,
  estimateRetainedAiCharactersFromAcceptedResponses,
} from "@/lib/metrics";
import { extractPlainText } from "@/lib/tiptap-utils";

export const revalidate = 86400; // 24h cache — badge data is immutable; takedown triggers on-demand revalidation
import { StatsSummary } from "@/components/verify/StatsSummary";
import { AuditTimeline } from "@/components/verify/AuditTimeline";
import { ScopeStatement } from "@/components/verify/ScopeStatement";
import { DocumentText } from "@/components/verify/DocumentText";

interface BadgeStats {
  ai_percentage: number;
  aiPercentage?: number;
  external_paste_percentage: number;
  interaction_count: number;
  session_count: number;
  total_active_seconds: number;
  total_characters: number;
}

interface AuditTrail {
  ai_interactions: Array<{
    mode: string;
    prompt: string;
    response: string;
    action: string;
    createdAt: string | Date | null;
  }>;
  paste_events: Array<{
    sourceType: string;
    characterCount: number;
    createdAt: string | Date | null;
  }>;
  writing_sessions: Array<{
    startedAt: string | Date | null;
    endedAt: string | Date | null;
    activeSeconds: number | null;
  }>;
  revisions: Array<{
    trigger: string;
    createdAt: string | Date | null;
  }>;
}

export default async function VerifyPage({
  params,
}: {
  params: Promise<{ id: string }>;
}) {
  const { id } = await params;

  const [badge] = await db
    .select()
    .from(badges)
    .where(eq(badges.verificationId, id));

  if (!badge) {
    notFound();
  }

  // Handle taken-down badges
  if (badge.isTakenDown) {
    return (
      <div className="mx-auto max-w-2xl px-4 py-16 text-center">
        <h1 className="mb-4 text-2xl font-bold">Badge Removed</h1>
        <p className="text-muted-foreground">
          This badge has been taken down by the document owner.
          {badge.takedownReason && (
            <span className="mt-2 block">
              Reason: {badge.takedownReason}
            </span>
          )}
        </p>
      </div>
    );
  }

  const stats = badge.stats as BadgeStats;
  const auditTrail = badge.auditTrail as AuditTrail;
  const documentContent =
    badge.documentContent as Parameters<typeof calculateMetrics>[0];

  const calculatedMetrics = calculateMetrics(documentContent);
  const finalTextSnapshot =
    badge.documentText ?? extractPlainText(documentContent);
  const fallbackAiChars = estimateRetainedAiCharactersFromAcceptedResponses(
    finalTextSnapshot,
    auditTrail.ai_interactions ?? []
  );
  const fallbackAiPercentage =
    calculatedMetrics.total_characters > 0
      ? Math.floor(
          (Math.min(fallbackAiChars, calculatedMetrics.total_characters) /
            calculatedMetrics.total_characters) *
            100
        )
      : 0;
  const resolvedAiPercentage = Math.max(
    stats.ai_percentage ?? stats.aiPercentage ?? 0,
    calculatedMetrics.ai_percentage,
    fallbackAiPercentage
  );
  const resolvedExternalPastePercentage = Math.max(
    stats.external_paste_percentage ?? 0,
    calculatedMetrics.external_paste_percentage
  );
  const resolvedTotalCharacters = Math.max(
    stats.total_characters ?? 0,
    calculatedMetrics.total_characters
  );

  return (
    <div className="mx-auto max-w-3xl px-4 py-6 sm:py-8">
      {/* Sticky mobile header */}
      <nav className="sticky top-0 z-10 -mx-4 mb-4 border-b bg-background px-4 py-2 sm:hidden" aria-label="Site navigation">
        <Link href="/" className="flex items-center justify-center gap-2">
          <span className="text-base font-bold text-provenance-700">◆</span>
          <span className="text-xs font-medium text-provenance-700">Provenance</span>
          <span className="font-mono text-xs text-muted-foreground">{id.slice(0, 8)}...</span>
        </Link>
      </nav>

      {/* Verification header with logo + ID */}
      <header className="mb-6 sm:mb-8 -mx-4 px-4 pt-6 pb-8 bg-gradient-to-b from-provenance-50/60 to-transparent">
        <Link href="/" className="flex items-center justify-center gap-2 mb-2">
          <span className="text-lg font-bold text-provenance-700">◆</span>
          <span className="text-sm font-medium text-provenance-700">Provenance</span>
        </Link>
        <h1 className="text-center text-xl font-bold tracking-tight sm:text-2xl">Verified Writing Process</h1>
        <p className="mt-1 text-center font-mono text-xs text-muted-foreground">
          {id}
        </p>
        <p className="mt-1 text-center text-sm text-muted-foreground">
          {badge.documentTitle}
        </p>
      </header>

      <section className="mb-6 sm:mb-8">
        <StatsSummary
          stats={{
            ai_percentage: resolvedAiPercentage,
            external_paste_percentage: resolvedExternalPastePercentage,
            interaction_count: stats.interaction_count ?? 0,
            session_count: stats.session_count ?? 0,
            total_active_seconds: stats.total_active_seconds ?? 0,
            total_characters: resolvedTotalCharacters,
          }}
        />
      </section>

      <section className="mb-6 sm:mb-8">
        <ScopeStatement />
      </section>

      <section className="mb-6 sm:mb-8">
        <h2 className="mb-3 text-lg font-semibold tracking-tight">Document</h2>
        <DocumentText
          title={badge.documentTitle}
          text={badge.documentText}
        />
