      <section className="mb-6 sm:mb-8">
        <h2 className="mb-3 text-lg font-semibold tracking-tight">Audit Timeline</h2>
        <AuditTimeline
          interactions={auditTrail.ai_interactions ?? []}
          pasteEvents={auditTrail.paste_events ?? []}
          sessions={auditTrail.writing_sessions ?? []}
          revisions={auditTrail.revisions ?? []}
        />
      </section>

      <footer className="border-t pt-4 text-center text-xs text-muted-foreground">
        Powered by{" "}
        <Link href="/" className="font-medium text-provenance-700 hover:underline">
          Provenance
        </Link>
        {" "}— Transparent AI writing verification
      </footer>
    </div>
  );
}

"use client";

import { cn } from "@/lib/utils";
import Link from "next/link";
import { Trash2 } from "lucide-react";

interface DocumentRowProps {
  id: string;
  title: string;
  updatedAt: string | Date | null;
  wordCount: number | null;
  preview?: string;
  aiPercentage?: number | null;
  hasBadge: boolean;
  latestBadgeVerificationId?: string | null;
  isArchived?: boolean;
  onClick?: () => void;
  onDelete?: (id: string) => void;
}

function getAIBadgeColor(percentage: number): string {
  if (percentage <= 25) return "bg-emerald-50 text-emerald-700";
  if (percentage <= 50) return "bg-amber-50 text-amber-700";
  if (percentage <= 75) return "bg-orange-50 text-orange-700";
  return "bg-red-50 text-red-700";
}

function relativeDate(date: string | Date | null): string {
  if (!date) return "";
  const d = new Date(date);
  const now = new Date();
  const diffMs = now.getTime() - d.getTime();
  const diffMins = Math.floor(diffMs / 60000);
  const diffHours = Math.floor(diffMs / 3600000);
  const diffDays = Math.floor(diffMs / 86400000);

  if (diffMins < 1) return "just now";
  if (diffMins < 60) return `${diffMins}m ago`;
  if (diffHours < 24) return `${diffHours}h ago`;
  if (diffDays < 7) return `${diffDays}d ago`;
  return d.toLocaleDateString();
}

export function DocumentRow({
  id,
  title,
  updatedAt,
  wordCount,
  preview,
  aiPercentage,
  hasBadge,
  latestBadgeVerificationId,
  isArchived,
  onClick,
  onDelete,
}: DocumentRowProps) {
  return (
    <div
      onClick={onClick}
      role="button"
      tabIndex={0}
      onKeyDown={(e) => { if (e.key === "Enter" || e.key === " ") onClick?.(); }}
      className={cn(
        "flex w-full items-start gap-3 border-b border-border px-4 py-3 text-left hover:bg-muted cursor-pointer transition-colors duration-150",
        isArchived && "opacity-60"
      )}
    >
      {/* Status dot */}
      <span
        className={cn(
          "mt-1.5 inline-block h-2.5 w-2.5 shrink-0 rounded-full",
          hasBadge ? "bg-emerald-500" : isArchived ? "bg-muted-foreground/30" : "bg-muted-foreground/50"
        )}
      />

      <div className="min-w-0 flex-1">
        <div className="flex items-center justify-between gap-2">
          <span className="truncate text-sm font-medium">{title || "Untitled"}</span>
          <div className="flex shrink-0 items-center gap-2">
            <span className="text-xs text-muted-foreground">
              {relativeDate(updatedAt)}
            </span>
            {onDelete && (
              <button
                onClick={(e) => {
                  e.stopPropagation();
                  onDelete(id);
                }}
                className="rounded p-1 text-muted-foreground hover:bg-red-50 hover:text-red-600 transition-colors duration-150"
                aria-label={`Delete ${title || "Untitled"}`}
              >
                <Trash2 className="h-3.5 w-3.5" />
              </button>
            )}
          </div>
        </div>

        {preview && (
          <p className="mt-0.5 truncate text-xs text-muted-foreground">{preview}</p>
        )}

        <div className="mt-1 flex items-center gap-2">
          {aiPercentage != null && (
            <span className={`rounded px-1.5 py-0.5 text-xs font-medium font-mono tabular-nums ${getAIBadgeColor(aiPercentage)}`}>
              {aiPercentage}% AI
            </span>
          )}
          {wordCount != null && (
            <span className="text-xs text-muted-foreground font-mono tabular-nums">
              {wordCount.toLocaleString()} words
            </span>
          )}
          {latestBadgeVerificationId && (
            <Link
              href={`/verify/${latestBadgeVerificationId}`}
              className="rounded px-1.5 py-0.5 text-xs font-medium text-provenance-700 hover:bg-provenance-50 hover:text-provenance-800"
              onClick={(e) => e.stopPropagation()}
            >
              View badge
            </Link>
          )}
        </div>
      </div>
    </div>
  );
}

"use client";

import { useState, useEffect, useCallback, useRef } from "react";
import { useEditor, EditorContent } from "@tiptap/react";
import StarterKit from "@tiptap/starter-kit";
import Link from "@tiptap/extension-link";
import Image from "@tiptap/extension-image";
import Placeholder from "@tiptap/extension-placeholder";
import { OriginMark } from "@/extensions/origin-mark";
import { PasteHandler } from "@/extensions/paste-handler";
import { EditorInteractionPolicy } from "@/extensions/interaction-policy";
import {
  SelectionHighlight,
  selectionHighlightKey,
} from "@/extensions/selection-highlight";
import { logPasteEvent } from "@/app/actions/paste-events";
import { useRevisions } from "@/hooks/useRevisions";
import { Toolbar } from "./Toolbar";
import { InlineAI } from "./InlineAI";
import { TimelineModal } from "./TimelineModal";
import { ChatPanel } from "./chat/ChatPanel";
import { CollapseRail } from "./CollapseRail";
import {
  ResizablePanelGroup,
  ResizablePanel,
  ResizableHandle,
} from "@/components/ui/resizable";
import type { PanelImperativeHandle } from "react-resizable-panels";
import { Sparkle } from "lucide-react";

interface ThreadSummary {
  id: string;
  title: string;
  messageCount: number | null;
  updatedAt: Date | null;
}

interface EditorProps {
  content: Record<string, unknown>;
  documentId: string;
  provider?: string;
  model?: string;
  chatOpen?: boolean;
  onChatToggle?: () => void;
  editorOpen?: boolean;
  onEditorToggle?: () => void;
  initialChatThreads?: ThreadSummary[];
  onUpdate?: (json: Record<string, unknown>) => void;
}

interface TextSelection {
  text: string;
  from: number;
  to: number;
}

interface TriggerPosition {
  top: number;
  left: number;
  right: number;
}

function areSelectionsEqual(
  current: TextSelection | null,
  next: TextSelection | null
): boolean {
  if (current === next) return true;
  if (!current || !next) return false;
  return (
    current.text === next.text &&
    current.from === next.from &&
    current.to === next.to
  );
}

function hasDocumentText(content: unknown): boolean {
  if (!content || typeof content !== "object") return false;
  const stack: unknown[] = [content];

  while (stack.length > 0) {
    const node = stack.pop();
    if (!node || typeof node !== "object") continue;
    const record = node as { text?: unknown; content?: unknown[] };

    if (typeof record.text === "string" && record.text.trim().length > 0) {
      return true;
    }

    if (Array.isArray(record.content)) {
      stack.push(...record.content);
    }
  }

  return false;
}

function timelineStateKey(documentId: string): string {
  return `provenance:editor:${documentId}:timeline-open`;
}

function readTimelineOpenState(documentId: string): boolean {
  if (typeof window === "undefined") return false;
  return window.localStorage.getItem(timelineStateKey(documentId)) === "1";
}

export function Editor({
  content,
  documentId,
  onUpdate,
  provider = "anthropic",
  model,
  chatOpen = true,
  onChatToggle,
  editorOpen = true,
  onEditorToggle,
  initialChatThreads = [],
}: EditorProps) {
  const [selection, setSelection] = useState<TextSelection | null>(null);
  const [showInlineAI, setShowInlineAI] = useState(false);
  const [showTimeline, setShowTimeline] = useState(
    () => readTimelineOpenState(documentId)
  );
  const [showLens, setShowLens] = useState(false);
  const [hasContent, setHasContent] = useState(() => hasDocumentText(content));
  const [triggerPosition, setTriggerPosition] = useState<TriggerPosition>({
    top: 96,
    left: 0,
    right: 24,
  });
  const { updateContent, createAIRevision } = useRevisions({ documentId });
  const mainRef = useRef<HTMLElement>(null);
  const scrollAreaRef = useRef<HTMLDivElement>(null);
  const proseAreaRef = useRef<HTMLDivElement>(null);
  const contentRef = useRef<Record<string, unknown>>(content);
  const chatPanelRef = useRef<PanelImperativeHandle>(null);
  const editorPanelRef = useRef<PanelImperativeHandle>(null);
  const groupRef = useRef<HTMLDivElement>(null);
  const transitionTimeoutRef = useRef<ReturnType<typeof setTimeout>>(null);

  const getDocumentContent = useCallback(() => contentRef.current, []);
  const handleLensToggle = useCallback(() => setShowLens((v) => !v), []);

  // Animation helpers
  const clearPanelTransition = useCallback(() => {
    groupRef.current?.classList.remove("panel-transitioning");
    if (transitionTimeoutRef.current) {
      clearTimeout(transitionTimeoutRef.current);
      transitionTimeoutRef.current = null;
    }
  }, []);

  const startPanelTransition = useCallback(() => {
    const group = groupRef.current;
    if (!group) return;
    group.classList.add("panel-transitioning");

    // Listen for transitionend on any panel child
    const handleEnd = (e: TransitionEvent) => {
      if ((e.target as HTMLElement)?.hasAttribute("data-panel")) {
        clearPanelTransition();
        group.removeEventListener("transitionend", handleEnd);
      }
    };
    group.addEventListener("transitionend", handleEnd);

    // Safety fallback
    transitionTimeoutRef.current = setTimeout(clearPanelTransition, 300);
  }, [clearPanelTransition]);

  const handleExternalPaste = useCallback(
    (pastedContent: string, characterCount: number, sourceId: string) => {
      logPasteEvent({
        sourceId,
        documentId,
        content: pastedContent,
        sourceType: "external",
        characterCount,
      });
    },
    [documentId]
  );

  const editor = useEditor({
    extensions: [
      StarterKit.configure({
        heading: { levels: [1, 2, 3] },
      }),
      Link.configure({
        openOnClick: false,
        autolink: true,
        defaultProtocol: "https",
      }),
      Image.configure({ inline: false }),
      Placeholder.configure({
        placeholder: "Start writing...",
      }),
      OriginMark,
      SelectionHighlight,
      EditorInteractionPolicy,
      PasteHandler.configure({
        documentId,
        onExternalPaste: handleExternalPaste,
      }),
    ],
    content,
    immediatelyRender: false,
    onUpdate: ({ editor }) => {
      const json = editor.getJSON();
      contentRef.current = json;
      const nextHasContent = editor.state.doc.textContent.length > 0;
      setHasContent((prev) => (prev === nextHasContent ? prev : nextHasContent));
      onUpdate?.(json);
      updateContent(json);
    },
  });

  const updateTriggerPosition = useCallback(
    (position?: number) => {
      if (!editor || !mainRef.current) return;

      const main = mainRef.current;
      const proseArea = proseAreaRef.current;
      const mainRect = main.getBoundingClientRect();
      const proseRect = proseArea?.getBoundingClientRect();

      const iconSize = 32;
      const fallbackWidth = main.clientWidth || 1200;
      const fallbackHeight = main.clientHeight || 800;
      const targetPos = Math.max(1, position ?? editor.state.selection.from);

      try {
        const cursorCoords = editor.view.coordsAtPos(targetPos);
        const minTop = 56;
        const maxTop = Math.max(minTop, fallbackHeight - iconSize - 8);
        const nextTop = Math.min(
          maxTop,
          Math.max(minTop, cursorCoords.top - mainRect.top - 4)
        );

        const rightMarginAnchor = proseRect?.right
          ? proseRect.right - mainRect.left + 8
          : fallbackWidth - iconSize - 12;
        const nextLeft = Math.min(
          fallbackWidth - iconSize - 8,
          Math.max(8, rightMarginAnchor)
        );
        const nextRight = Math.max(8, fallbackWidth - nextLeft - iconSize);

        setTriggerPosition((prev) => {
          if (
            prev.top === nextTop &&
            prev.left === nextLeft &&
            prev.right === nextRight
          ) {
            return prev;
          }
          return {
            top: nextTop,
            left: nextLeft,
            right: nextRight,
          };
        });
      } catch {
        // Ignore transient invalid positions from TipTap while selection is updating.
      }
    },
    [editor]
  );

  useEffect(() => {
    if (!editor) return;
    const syncHasContent = () => {
      const nextHasContent = editor.state.doc.textContent.length > 0;
      setHasContent((prev) =>
        prev === nextHasContent ? prev : nextHasContent
      );
    };

    const handleSelectionUpdate = () => {
      const { from, to } = editor.state.selection;
      syncHasContent();
      updateTriggerPosition(to);
      const nextSelection =
        from !== to
          ? {
              text: editor.state.doc.textBetween(from, to),
              from,
              to,
            }
          : null;
      setSelection((prev) =>
        areSelectionsEqual(prev, nextSelection) ? prev : nextSelection
      );
      if (nextSelection === null) {
        setShowInlineAI((prev) => (prev ? false : prev));
      }
    };

    handleSelectionUpdate();
    editor.on("selectionUpdate", handleSelectionUpdate);
    return () => {
      editor.off("selectionUpdate", handleSelectionUpdate);
    };
  }, [editor, updateTriggerPosition]);

  useEffect(() => {
    if (!editor) return;
    const handleViewportChange = () => updateTriggerPosition();
    const scrollArea = scrollAreaRef.current;
    window.addEventListener("resize", handleViewportChange);
    scrollArea?.addEventListener("scroll", handleViewportChange, {
      passive: true,
    });
    return () => {
      window.removeEventListener("resize", handleViewportChange);
      scrollArea?.removeEventListener("scroll", handleViewportChange);
    };
  }, [editor, updateTriggerPosition]);

  // Dynamically toggle lens-off class on the ProseMirror editor root
  useEffect(() => {
    if (!editor) return;
    const el = editor.view.dom;
    if (showLens) {
      el.classList.remove("lens-off");
    } else {
      el.classList.add("lens-off");
    }
  }, [editor, showLens]);

  // Cmd+Shift+H keyboard shortcut for lens toggle, scoped to editor container
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (
        e.code === "KeyH" &&
        e.shiftKey &&
        (e.metaKey || e.ctrlKey) &&
        proseAreaRef.current?.contains(document.activeElement)
      ) {
        e.preventDefault();
        setShowLens((v) => !v);
      }
    };
    window.addEventListener("keydown", handleKeyDown);
    return () => window.removeEventListener("keydown", handleKeyDown);
  }, []);

  // Sync persistent selection highlight decoration with InlineAI visibility
  useEffect(() => {
    if (!editor?.view || !editor.state?.tr) return;
    try {
      if (showInlineAI && selection) {
        editor.view.dispatch(
          editor.state.tr.setMeta(selectionHighlightKey, {
            from: selection.from,
            to: selection.to,
            active: true,
          })
        );
      } else {
        editor.view.dispatch(
          editor.state.tr.setMeta(selectionHighlightKey, {
            from: 0,
            to: 0,
            active: false,
          })
        );
      }
    } catch {
      // Editor not fully initialized yet
    }
  }, [editor, showInlineAI, selection]);

  const handleDismissInlineAI = useCallback(() => {
    setShowInlineAI(false);
  }, []);

  const handleAITriggerClick = useCallback(() => {
    if (!selection?.text.trim()) return;
    editor
      ?.chain()
      .focus()
      .setTextSelection({ from: selection.from, to: selection.to })
      .run();
    setShowInlineAI(true);
  }, [editor, selection]);

  // Sync chatOpen prop with imperative panel handle
  useEffect(() => {
    startPanelTransition();
    if (chatOpen) {
      chatPanelRef.current?.expand();
      return;
    }
    chatPanelRef.current?.collapse();
  }, [chatOpen, startPanelTransition]);

  // Sync editorOpen prop with imperative panel handle
  useEffect(() => {
    startPanelTransition();
    if (editorOpen) {
      editorPanelRef.current?.expand();
      return;
    }
    editorPanelRef.current?.collapse();
  }, [editorOpen, startPanelTransition]);

  // Focus after expand
  useEffect(() => {
    if (chatOpen) {
      // Small delay to let panel animation finish before focusing
      const timer = setTimeout(() => {
        const input = groupRef.current?.querySelector<HTMLTextAreaElement>(
          '[data-testid="chat-input"], textarea'
        );
        input?.focus();
      }, 220);
      return () => clearTimeout(timer);
    }
  }, [chatOpen]);

  useEffect(() => {
    if (editorOpen) {
      const timer = setTimeout(() => {
        editor?.chain().focus().run();
      }, 220);
      return () => clearTimeout(timer);
    }
  }, [editorOpen, editor]);

  useEffect(() => {
    if (typeof window === "undefined") return;
    window.localStorage.setItem(
      timelineStateKey(documentId),
      showTimeline ? "1" : "0"
    );
  }, [documentId, showTimeline]);

  // ⌘L keyboard shortcut to toggle AI chat panel
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if ((e.metaKey || e.ctrlKey) && e.key === "l") {
        e.preventDefault();
        onChatToggle?.();
      }
    };
    window.addEventListener("keydown", handleKeyDown);
    return () => window.removeEventListener("keydown", handleKeyDown);
  }, [onChatToggle]);

  const handleRecentAIResponse = useCallback(
    (responseText: string) => {
      if (!editor) return;
      if (!responseText.trim()) return;
      editor.commands.addRecentAIResponse?.(responseText);
    },
    [editor]
  );

  const handleAIResponse = useCallback(
    (responseText: string) => {
      handleRecentAIResponse(responseText);
      void createAIRevision();
    },
    [handleRecentAIResponse, createAIRevision]
  );

  // Editor content JSX — shared between expanded panel and hidden mount
  const editorContent = (
    <main
      ref={mainRef}
      id="editor-content"
      tabIndex={-1}
      className="relative flex h-full w-full flex-col outline-none"
      role="main"
      data-testid="editor-main"
    >
      <Toolbar
        editor={editor}
        onHistoryClick={() => setShowTimeline(true)}
        showLens={showLens}
        onLensToggle={handleLensToggle}
        chatOpen={chatOpen}
        onChatToggle={onChatToggle}
        editorOpen={editorOpen}
        onEditorCollapse={onEditorToggle}
      />
      <div
        ref={scrollAreaRef}
        className="flex-1 cursor-text overflow-auto"
        onClick={(e) => {
          if (
            (e.target === scrollAreaRef.current || e.target === proseAreaRef.current) &&
            !editor?.state.selection.content().size
          ) {
            editor?.chain().focus("end").run();
          }
        }}
      >
        <div ref={proseAreaRef} className="mx-auto max-w-4xl px-8 py-8">
          <EditorContent
            editor={editor}
            data-testid="editor-surface"
            className="prose prose-neutral dark:prose-invert max-w-none focus-within:outline-none [&_.tiptap]:min-h-[60vh] [&_.tiptap]:outline-none"
          />
        </div>
      </div>

      {hasContent && (
        <button
          type="button"
          onMouseDown={(e) => {
            e.preventDefault();
          }}
          onClick={handleAITriggerClick}
          className="absolute z-40 flex h-8 w-8 cursor-pointer items-center justify-center rounded-full border border-violet-200 bg-background text-violet-600 shadow-sm transition-colors hover:bg-violet-50 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-provenance-500"
          style={{
            top: `${triggerPosition.top}px`,
            left: `${triggerPosition.left}px`,
          }}
          aria-label={
            selection?.text.trim()
              ? "Modify selected text with AI"
              : "AI assistant"
          }
          title={
            selection?.text.trim()
              ? "Modify selected text"
              : "AI assistant"
          }
          data-testid="inline-ai-trigger"
        >
          <Sparkle className="h-4 w-4" />
        </button>
      )}

      {showInlineAI && selection && editor && (
        <InlineAI
          editor={editor}
          documentId={documentId}
          provider={provider}
          model={model}
          selectedText={selection.text}
          selectionFrom={selection.from}
          selectionTo={selection.to}
          anchorTop={triggerPosition.top}
          anchorRight={triggerPosition.right}
          onDismiss={handleDismissInlineAI}
          onAIResponse={handleAIResponse}
        />
      )}
    </main>
  );

  const editorMinSize = editorOpen ? "40%" : "36px";
  const editorMaxSize = editorOpen ? "100%" : "36px";
  const chatMinSize = chatOpen ? "25%" : "36px";
  const chatMaxSize = chatOpen ? "100%" : "36px";

  return (
    <>
      <div ref={groupRef} className="flex min-h-0 w-full flex-1">
      <ResizablePanelGroup
        orientation="horizontal"
        className="min-h-0 w-full flex-1"
      >
        <ResizablePanel
          panelRef={editorPanelRef}
          defaultSize={editorOpen ? "65%" : "36px"}
          minSize={editorMinSize}
          maxSize={editorMaxSize}
          collapsible
          collapsedSize="36px"
        >
          {editorOpen ? (
            editorContent
          ) : (
            <CollapseRail label="Editor" onClick={() => onEditorToggle?.()} />
          )}
        </ResizablePanel>

        <ResizableHandle
          withHandle
          onCollapseToggle={!editorOpen ? undefined : onChatToggle}
          collapseDirection="right"
          isCollapsed={!chatOpen || !editorOpen}
          collapseLabel="AI Chat"
        />

        <ResizablePanel
          panelRef={chatPanelRef}
          defaultSize={chatOpen ? "35%" : "36px"}
          minSize={chatMinSize}
          maxSize={chatMaxSize}
          collapsible
          collapsedSize="36px"
          onResize={() => updateTriggerPosition()}
        >
          {chatOpen ? (
            <ChatPanel
              documentId={documentId}
              provider={provider}
              model={model}
              getDocumentContent={getDocumentContent}
              initialThreads={initialChatThreads}
              onAssistantResponse={handleRecentAIResponse}
              onClose={() => onChatToggle?.()}
            />
          ) : (
            <CollapseRail
              label="AI Chat"
              shortcut="⌘L"
              onClick={() => onChatToggle?.()}
            />
          )}
        </ResizablePanel>
      </ResizablePanelGroup>
      </div>

      {/* Hidden mount to preserve TipTap instance when editor panel is collapsed */}
      {!editorOpen && (
        <div className="hidden" aria-hidden="true">
          {editorContent}
        </div>
      )}

      <TimelineModal
        documentId={documentId}
        isOpen={showTimeline}
        onClose={() => setShowTimeline(false)}
      />
    </>
  );
}

"use client";

import { useState, useCallback, useEffect, useMemo } from "react";
import { useCompletion } from "@ai-sdk/react";
import type { Editor } from "@tiptap/react";
import { logAIInteraction } from "@/app/actions/ai-interactions";
import { Sparkles, Check } from "lucide-react";
import { Button } from "@/components/ui/button";
import { TrackChangesDiff } from "./TrackChangesDiff";

const PRESETS = [
  { label: "Improve", prompt: "Improve this text while keeping the same meaning" },
  { label: "Simplify", prompt: "Simplify this text to be more concise and clear" },
  { label: "Expand", prompt: "Expand on this text with more detail" },
  { label: "Fix", prompt: "Fix grammar, spelling, and clarity issues in this text" },
  { label: "More formal", prompt: "Rewrite this text in a more formal tone" },
  { label: "More casual", prompt: "Rewrite this text in a more casual tone" },
];

interface InlineAIProps {
  editor: Editor;
  documentId: string;
  provider: string;
  model?: string;
  selectedText: string;
  selectionFrom: number;
  selectionTo: number;
  anchorTop?: number;
  anchorRight?: number;
  onDismiss: () => void;
  onAIResponse?: (responseText: string) => void;
}

type Stage = "toolbar" | "choosing";

interface Choice {
  id: string;
  label: string;
  sublabel?: string;
  text: string;
  isOriginal: boolean;
}

function wordCount(text: string): number {
  return text.split(/\s+/).filter(Boolean).length;
}

function changeRatio(original: string, suggestion: string): number {
  const origWords = original.split(/\s+/).filter(Boolean);
  const suggWords = suggestion.split(/\s+/).filter(Boolean);
  const maxLen = Math.max(origWords.length, suggWords.length);
  if (maxLen === 0) return 0;
  // Count words in common using LCS length
  const m = origWords.length;
  const n = suggWords.length;
  const dp: number[][] = Array.from({ length: m + 1 }, () => Array(n + 1).fill(0));
  for (let i = 1; i <= m; i++) {
    for (let j = 1; j <= n; j++) {
      dp[i][j] = origWords[i - 1] === suggWords[j - 1]
        ? dp[i - 1][j - 1] + 1
        : Math.max(dp[i - 1][j], dp[i][j - 1]);
    }
  }
  const common = dp[m][n];
  return 1 - common / maxLen;
}

const DIFF_THRESHOLD = 0.25;

function createSourceId(): string {
  if (globalThis.crypto?.randomUUID) {
    return globalThis.crypto.randomUUID();
  }

  return "xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx".replace(/[xy]/g, (char) => {
    const rand = Math.floor(Math.random() * 16);
    const value = char === "x" ? rand : (rand & 0x3) | 0x8;
    return value.toString(16);
  });
}

function cleanSuggestionText(text: string): string {
  return text
    .replace(/^\s*(SUGGESTION|OPTION)\s*\d+\s*:\s*/i, "")
    .trim();
}

function parseSuggestions(rawCompletion: string): [string, string] {
  const completion = rawCompletion.trim();
  if (!completion) return ["", ""];

  const delimiterMatch = completion
    .split(/\n-{3,}\n/)
    .map((part) => cleanSuggestionText(part))
    .filter(Boolean);
  if (delimiterMatch.length >= 2) {
    return [delimiterMatch[0], delimiterMatch[1]];
  }

  const explicitMatch = completion.match(
    /SUGGESTION\s*1\s*:\s*([\s\S]*?)\n+\s*SUGGESTION\s*2\s*:\s*([\s\S]*)/i
  );
  if (explicitMatch) {
    return [
      cleanSuggestionText(explicitMatch[1]),
      cleanSuggestionText(explicitMatch[2]),
    ];
  }

  const blocks = completion
    .split(/\n{2,}/)
    .map((part) => cleanSuggestionText(part))
    .filter(Boolean);
  if (blocks.length >= 2) {
    return [blocks[0], blocks[1]];
  }

  return [cleanSuggestionText(completion), cleanSuggestionText(completion)];
}

function suggestionDeltaLabel(originalText: string, suggestionText: string): string | undefined {
  const originalWords = wordCount(originalText);
  const suggestionWords = wordCount(suggestionText);
  const diff = originalWords - suggestionWords;
  if (diff > 0) return `· ${diff} fewer word${diff !== 1 ? "s" : ""}`;
  if (diff < 0) return `· ${Math.abs(diff)} more word${Math.abs(diff) !== 1 ? "s" : ""}`;
  return undefined;
}

export function InlineAI({
  editor,
  documentId,
  provider,
  model,
  selectedText,
  selectionFrom,
  selectionTo,
  anchorTop = 96,
  anchorRight = 24,
  onDismiss,
  onAIResponse,
}: InlineAIProps) {
  const [stage, setStage] = useState<Stage>("toolbar");
  const [promptText, setPromptText] = useState("");
  const [lastPrompt, setLastPrompt] = useState("");
  const [activeAction, setActiveAction] = useState("");
  const [selectedChoiceId, setSelectedChoiceId] = useState("original");
  const [error, setError] = useState<string | null>(null);

  const { completion, complete, isLoading, setCompletion, stop } =
    useCompletion({
      api: "/api/ai/complete",
      onError: (err) => {
        const message = err.message || "AI request failed";
        if (message.includes("429") || message.includes("rate limit")) {
          setError("Rate limit exceeded. Please wait a moment and retry.");
        } else if (message.includes("502") || message.includes("503")) {
          setError("AI provider is temporarily unavailable. Please retry.");
        } else {
          setError("Something went wrong. Please try again.");
        }
      },
    });

  const choices = useMemo<Choice[]>(() => {
    if (!completion) return [];
    const [suggestionOne, suggestionTwo] = parseSuggestions(completion);

    return [
      {
        id: "original",
        label: "YOUR ORIGINAL",
        text: selectedText,
        isOriginal: true,
      },
      {
        id: "suggestion-1",
        label: "SUGGESTION 1",
        sublabel: suggestionDeltaLabel(selectedText, suggestionOne),
        text: suggestionOne,
        isOriginal: false,
      },
      {
        id: "suggestion-2",
        label: "SUGGESTION 2",
        sublabel: suggestionDeltaLabel(selectedText, suggestionTwo),
        text: suggestionTwo,
        isOriginal: false,
      },
    ];
  }, [completion, selectedText]);

  const handleSubmit = useCallback(
    async (prompt: string, actionName: string) => {
      setLastPrompt(prompt);
      setActiveAction(actionName);
      setError(null);
      setStage("choosing");
      setSelectedChoiceId("original"); // Original starts selected
      const dualSuggestionPrompt = `${prompt}

Return exactly TWO distinct rewritten options for the selected text.
Do not include explanations.
Use this format exactly:
SUGGESTION 1:
<text>
---
SUGGESTION 2:
<text>`;
      await complete(dualSuggestionPrompt, {
        body: {
          mode: "inline",
          provider,
          model,
          selectedText,
        },
      });
    },
    [complete, provider, model, selectedText]
  );

  const handleConfirm = useCallback(async () => {
    const selected = choices.find((c) => c.id === selectedChoiceId);
    if (!selected) return;

    if (selected.isOriginal) {
      // Kept original — log as rejected, no editor change
      if (completion) {
        void logAIInteraction({
          documentId,
          mode: "inline",
          prompt: lastPrompt,
          selectedText,
          response: completion,
          action: "rejected",
          provider,
          model: model ?? "",
          charactersInserted: 0,
        });
      }
      setCompletion("");
      onDismiss();
      return;
    }

    // Accepted AI suggestion
    const sourceId = createSourceId();

    await logAIInteraction({
      sourceId,
      documentId,
      mode: "inline",
      prompt: lastPrompt,
      selectedText,
      response: selected.text,
      action: "accepted",
      provider,
      model: model ?? "",
      charactersInserted: selected.text.length,
    });

    editor
      .chain()
      .focus()
      .insertContentAt({ from: selectionFrom, to: selectionTo }, [
        {
          type: "text",
          text: selected.text,
          marks: [
            {
              type: "origin",
              attrs: {
                type: "ai",
                sourceId,
                originalLength: selected.text.length,
                originalText: selected.text,
              },
            },
          ],
        },
      ])
      .run();

    onAIResponse?.(selected.text);
    setCompletion("");
    onDismiss();
  }, [
    choices,
    selectedChoiceId,
    completion,
    editor,
    selectionFrom,
    selectionTo,
    documentId,
    lastPrompt,
    selectedText,
    provider,
    model,
    onAIResponse,
    setCompletion,
    onDismiss,
  ]);

  const handleDismiss = useCallback(() => {
    if (isLoading) stop();
    if (completion) {
      void logAIInteraction({
        documentId,
        mode: "inline",
        prompt: lastPrompt,
        selectedText,
        response: completion,
        action: "rejected",
        provider,
        model: model ?? "",
        charactersInserted: 0,
      });
    }
    setCompletion("");
    onDismiss();
  }, [isLoading, stop, completion, documentId, lastPrompt, selectedText, provider, model, setCompletion, onDismiss]);

  // Keyboard: ↑↓ navigate, Enter confirm, Escape dismiss
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key === "Escape") {
        e.preventDefault();
        handleDismiss();
        return;
      }

      if (stage === "choosing" && choices.length > 0) {
        if (e.key === "ArrowUp" || e.key === "ArrowDown") {
          e.preventDefault();
          const idx = choices.findIndex((c) => c.id === selectedChoiceId);
          const next =
            e.key === "ArrowDown"
              ? (idx + 1) % choices.length
              : (idx - 1 + choices.length) % choices.length;
          setSelectedChoiceId(choices[next].id);
        }
        if (e.key === "Enter" && !isLoading) {
          e.preventDefault();
          handleConfirm();
        }
      }
    };
    window.addEventListener("keydown", handleKeyDown);
    return () => window.removeEventListener("keydown", handleKeyDown);
  }, [stage, choices, selectedChoiceId, isLoading, handleDismiss, handleConfirm]);

  // Stage 1: Floating toolbar with presets
  if (stage === "toolbar") {
    return (
      <div
        className="floating-toolbar absolute z-50 w-[calc(100%-2rem)] max-w-md rounded-lg border bg-background p-3 shadow-lg"
        style={{ top: `${anchorTop + 36}px`, right: `${anchorRight}px` }}
        data-testid="inline-ai-toolbar"
      >
        <div className="mb-2 flex items-center gap-2 text-xs text-muted-foreground">
          <Sparkles className="h-3.5 w-3.5 text-violet-500" />
          <span>
            Selection · {wordCount(selectedText)} word{wordCount(selectedText) !== 1 ? "s" : ""}
          </span>
        </div>

        <div className="mb-2 flex flex-wrap gap-1">
          {PRESETS.map((preset) => (
            <Button
              key={preset.label}
              variant="outline"
              size="xs"
              onClick={() => handleSubmit(preset.prompt, preset.label)}
            >
              {preset.label}
            </Button>
          ))}
        </div>

        <form
          onSubmit={(e) => {
            e.preventDefault();
            if (promptText.trim()) handleSubmit(promptText, "Custom");
          }}
        >
          <input
            value={promptText}
            onChange={(e) => setPromptText(e.target.value)}
            placeholder="Custom prompt..."
            className="w-full rounded-md border px-2 py-1 text-sm"
            autoFocus
          />
        </form>

        <div className="mt-2 flex justify-end">
          <button
            onClick={handleDismiss}
            className="text-xs text-muted-foreground hover:text-foreground transition-colors duration-150"
          >
            Cancel
          </button>
        </div>
      </div>
    );
  }

  // Stage 2: Card-based selection — "choose among equals"
  const sentenceCount = selectedText.split(/[.!?]+/).filter((s) => s.trim()).length;

  return (
    <div
      className="floating-toolbar absolute z-50 flex w-[calc(100%-2rem)] max-w-lg flex-col overflow-hidden rounded-xl border bg-background shadow-lg"
      style={{ top: `${anchorTop + 36}px`, right: `${anchorRight}px`, maxHeight: `calc(100% - ${anchorTop + 36}px - 8px)` }}
      data-testid="inline-ai-chooser"
    >
      {/* Header bar */}
      <div className="flex shrink-0 items-center justify-between border-b bg-muted px-4 py-2">
        <div className="flex items-center gap-2 text-sm">
          <Sparkles className="h-3.5 w-3.5 text-violet-500" />
          <span className="font-medium">{activeAction}</span>
          <span className="text-muted-foreground">
            · Selection · {sentenceCount} sentence{sentenceCount !== 1 ? "s" : ""}
          </span>
        </div>
      </div>

      {/* Choice cards */}
      <div className="min-h-0 overflow-y-auto p-3 space-y-2">
        {isLoading && choices.length === 0 && (
          <div className="py-4 text-center text-sm text-muted-foreground">
            Generating suggestion...
          </div>
        )}

        {error && !isLoading && (
          <div className="rounded-md bg-destructive/10 p-2 text-sm text-destructive">
            <p>{error}</p>
            <button
              onClick={() => lastPrompt && handleSubmit(lastPrompt, activeAction)}
              className="mt-1 font-medium underline hover:no-underline"
            >
              Retry
            </button>
          </div>
        )}

        {choices.map((choice) => {
          const isSelected = selectedChoiceId === choice.id;
          return (
            <button
              key={choice.id}
              onClick={() => setSelectedChoiceId(choice.id)}
              className={`relative w-full rounded-lg border-2 p-3 text-left text-sm transition-colors ${
                isSelected
                  ? "border-provenance-500 bg-provenance-500/5"
                  : "border-border hover:border-violet-300"
              }`}
              data-testid={`choice-${choice.id}`}
            >
              {/* Selection checkmark */}
              {isSelected && (
                <div className="absolute right-2 top-2 flex h-5 w-5 items-center justify-center rounded-full bg-provenance-500 text-white">
                  <Check className="h-3 w-3" />
                </div>
              )}

              {/* Label */}
              <div className="mb-1 flex items-center gap-2">
                <span
                  className={`text-xs font-semibold uppercase tracking-wider ${
                    choice.isOriginal ? "text-muted-foreground" : "text-violet-500"
                  }`}
                >
                  {choice.label}
                </span>
                {choice.sublabel && (
                  <span className="text-xs text-muted-foreground">
                    {choice.sublabel}
                  </span>
                )}
              </div>

              {/* Text content — show inline diff only for light edits */}
              <div className="text-foreground">
                {choice.isOriginal || changeRatio(selectedText, choice.text) >= DIFF_THRESHOLD ? (
                  <span className="whitespace-pre-wrap">{choice.text}</span>
                ) : (
                  <TrackChangesDiff original={selectedText} suggestion={choice.text} />
                )}
              </div>
            </button>
          );
        })}
      </div>

      {/* Footer bar */}
      {choices.length > 0 && (
        <div className="flex shrink-0 items-center justify-between border-t bg-muted px-4 py-2">
          <span className="text-xs text-muted-foreground">
            <kbd className="rounded border px-1">↑↓</kbd> navigate ·{" "}
            <kbd className="rounded border px-1">Enter</kbd> confirm ·{" "}
            <kbd className="rounded border px-1">Esc</kbd> dismiss
          </span>
          <Button
            variant="provenance"
            size="sm"
            onClick={handleConfirm}
            disabled={isLoading}
          >
            Confirm Selection
          </Button>
        </div>
      )}
    </div>
  );
}

