            type="button"
            disabled={editorOpen === true && !chatOpen}
          >
            <PanelLeftClose className="h-4 w-4" />
          </Button>
        )}

        {/* AI panel toggle — only shown when panel is collapsed */}
        {!chatOpen && (
          <>
            <div className="mx-1 w-px self-stretch bg-border" />
            <Button
              variant="outline"
              size="sm"
              onMouseDown={(e) => e.preventDefault()}
              onClick={onChatToggle}
              title="Toggle AI panel (⌘L)"
              type="button"
              className="flex items-center gap-2 text-xs"
            >
              <Sparkle className="h-3.5 w-3.5" />
              <span>AI</span>
              <kbd className="rounded border border-border bg-secondary px-1.5 py-0.5 text-xs font-medium text-muted-foreground">
                ⌘L
              </kbd>
            </Button>
          </>
        )}
      </div>
    </div>
  );
}

"use client";

interface TrackChangesDiffProps {
  original: string;
  suggestion: string;
}

interface DiffSegment {
  type: "equal" | "remove" | "add";
  text: string;
}

function tokenize(text: string): string[] {
  // Split into words and whitespace, preserving boundaries
  return text.match(/\S+|\s+/g) || [];
}

/**
 * Simple word-level diff using longest common subsequence.
 * Compares tokens (words + whitespace) between original and suggestion.
 */
function computeWordDiff(original: string, suggestion: string): DiffSegment[] {
  const origTokens = tokenize(original);
  const suggTokens = tokenize(suggestion);

  // Build LCS table
  const m = origTokens.length;
  const n = suggTokens.length;
  const dp: number[][] = Array.from({ length: m + 1 }, () => Array(n + 1).fill(0));

  for (let i = 1; i <= m; i++) {
    for (let j = 1; j <= n; j++) {
      if (origTokens[i - 1] === suggTokens[j - 1]) {
        dp[i][j] = dp[i - 1][j - 1] + 1;
      } else {
        dp[i][j] = Math.max(dp[i - 1][j], dp[i][j - 1]);
      }
    }
  }

  // Backtrack to find diff
  const segments: DiffSegment[] = [];
  let i = m;
  let j = n;

  const raw: DiffSegment[] = [];
  while (i > 0 || j > 0) {
    if (i > 0 && j > 0 && origTokens[i - 1] === suggTokens[j - 1]) {
      raw.push({ type: "equal", text: origTokens[i - 1] });
      i--;
      j--;
    } else if (j > 0 && (i === 0 || dp[i][j - 1] >= dp[i - 1][j])) {
      raw.push({ type: "add", text: suggTokens[j - 1] });
      j--;
    } else {
      raw.push({ type: "remove", text: origTokens[i - 1] });
      i--;
    }
  }

  raw.reverse();

  // Merge adjacent segments of the same type
  for (const seg of raw) {
    const last = segments[segments.length - 1];
    if (last && last.type === seg.type) {
      last.text += seg.text;
    } else {
      segments.push({ ...seg });
    }
  }

  return segments;
}

export function TrackChangesDiff({ original, suggestion }: TrackChangesDiffProps) {
  if (original === suggestion) {
    return <span>{suggestion}</span>;
  }

  const segments = computeWordDiff(original, suggestion);

  return (
    <span className="whitespace-pre-wrap">
      {segments.map((seg, i) => {
        if (seg.type === "equal") {
          return <span key={i}>{seg.text}</span>;
        }
        if (seg.type === "remove") {
          return (
            <span key={i} className="diff-remove">
              {seg.text}
            </span>
          );
        }
        return (
          <span key={i} className="diff-add">
            {seg.text}
          </span>
        );
      })}
    </span>
  );
}

"use client";

import { useState, useCallback, useRef, useEffect, useMemo } from "react";
import { useChat } from "@ai-sdk/react";
import { DefaultChatTransport } from "ai";
import type { UIMessage } from "ai";
import { ChatHeader } from "./ChatHeader";
import { ChatMessage } from "./ChatMessage";
import { ChatInput } from "./ChatInput";
import { ChatEmptyState } from "./ChatEmptyState";
import {
  getChatThread,
  saveChatThread,
} from "@/app/actions/chat-threads";

interface ThreadSummary {
  id: string;
  title: string;
  messageCount: number | null;
  updatedAt: Date | null;
}

interface ChatPanelProps {
  documentId: string;
  provider: string;
  model?: string;
  getDocumentContent: () => Record<string, unknown>;
  initialThreads: ThreadSummary[];
  onAssistantResponse?: (responseText: string) => void;
  onClose: () => void;
}

function extractPlainTextFromContent(
  content: Record<string, unknown>
): string {
  const extract = (node: Record<string, unknown>): string => {
    if (node.text && typeof node.text === "string") return node.text;
    if (Array.isArray(node.content)) {
      return node.content.map((child) => extract(child)).join("");
    }
    return "";
  };
  return extract(content);
}

function getTextFromMessage(message: UIMessage): string {
  return message.parts
    .filter((p): p is { type: "text"; text: string } => p.type === "text")
    .map((p) => p.text)
    .join("");
}

export function ChatPanel({
  documentId,
  provider,
  model,
  getDocumentContent,
  initialThreads,
  onAssistantResponse,
  onClose,
}: ChatPanelProps) {
  const [threads, setThreads] = useState<ThreadSummary[]>(initialThreads);
  const [activeThreadId, setActiveThreadId] = useState<string | null>(null);
  const [selectedProvider, setSelectedProvider] = useState(provider);
  const [selectedModel, setSelectedModel] = useState(model);
  const [inputValue, setInputValue] = useState("");
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const startTimeRef = useRef<number>(0);
  const streamThreadIdRef = useRef<string | null>(null);
  const savingRef = useRef(false);

  const getDocumentContext = useCallback(
    () => extractPlainTextFromContent(getDocumentContent()),
    [getDocumentContent]
  );

  const wordCount = useMemo(
    () => getDocumentContext().split(/\s+/).filter(Boolean).length,
    // eslint-disable-next-line react-hooks/exhaustive-deps
    [getDocumentContent]
  );

  const handleModelChange = useCallback(
    (newProvider: string, newModel: string) => {
      setSelectedProvider(newProvider);
      setSelectedModel(newModel);
    },
    []
  );

  const transportRef = useRef({ getDocumentContext, activeThreadId, selectedProvider, selectedModel });
  transportRef.current = { getDocumentContext, activeThreadId, selectedProvider, selectedModel };

  const transport = useMemo(
    () =>
      new DefaultChatTransport({
        api: "/api/chat",
        prepareSendMessagesRequest: ({ messages: msgs, id }) => ({
          body: {
            id,
            messages: msgs,
            documentContext: transportRef.current.getDocumentContext(),
            ...(transportRef.current.activeThreadId
              ? { threadId: transportRef.current.activeThreadId }
              : {}),
            provider: transportRef.current.selectedProvider,
            model: transportRef.current.selectedModel,
          },
        }),
      }),
    []
  );

  const {
    messages,
    setMessages,
    sendMessage,
    status,
    stop,
  } = useChat({
    transport,
    experimental_throttle: 50,
    onFinish: async ({ message, messages: allMessages }) => {
      const threadId = streamThreadIdRef.current;
      const assistantText = getTextFromMessage(message).trim();
      if (assistantText) {
        onAssistantResponse?.(assistantText);
      }

      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      const metadata = message.metadata as Record<string, any> | undefined;
      const elapsed = Math.round((Date.now() - startTimeRef.current) / 60000);

      const firstUserMsg = allMessages.find((m) => m.role === "user");
      const title = firstUserMsg
        ? getTextFromMessage(firstUserMsg).slice(0, 50) || "New conversation"
        : "New conversation";

      if (!threadId && savingRef.current) return;
      savingRef.current = true;

      try {
        const saved = await saveChatThread({
          documentId,
          threadId: threadId ?? undefined,
          title,
          messages: allMessages,
          messageCount: allMessages.length,
          summary: {
            messageCount: allMessages.length,
            durationMinutes: elapsed,
            category: "ask",
            provider: metadata?.provider ?? selectedProvider,
            model: metadata?.model ?? selectedModel ?? "",
            ...(metadata?.tokenCount
              ? { tokenCount: metadata.tokenCount }
              : {}),
          },
        });

        if (!threadId && saved) {
          setActiveThreadId(saved.id);
          streamThreadIdRef.current = saved.id;
          setThreads((prev) => [
            {
              id: saved.id,
              title: saved.title,
              messageCount: saved.messageCount,
              updatedAt: saved.updatedAt,
            },
            ...prev,
          ]);
        } else if (saved) {
          setThreads((prev) =>
            prev.map((t) =>
              t.id === saved.id
                ? {
                    ...t,
                    title: saved.title,
                    messageCount: saved.messageCount,
                    updatedAt: saved.updatedAt,
                  }
                : t
            )
          );
        }
      } catch (err) {
        console.error("[ChatPanel] Failed to save thread:", err);
      } finally {
        savingRef.current = false;
      }
    },
  });

  const isStreaming = status === "streaming";

  useEffect(() => {
    if (initialThreads.length === 0) {
      if (!startTimeRef.current) startTimeRef.current = Date.now();
      return;
    }

    let cancelled = false;
    const latestThreadId = initialThreads[0]?.id;
    if (!latestThreadId) return;

    void (async () => {
      try {
        const thread = await getChatThread(latestThreadId);
        if (cancelled) return;
        setActiveThreadId(thread.id);
        streamThreadIdRef.current = thread.id;
        setMessages((thread.messages ?? []) as UIMessage[]);
        startTimeRef.current = Date.now();
      } catch (err) {
        if (!cancelled) {
          console.error("[ChatPanel] Failed to restore latest thread:", err);
        }
      }
    })();

    return () => {
      cancelled = true;
    };
  }, [initialThreads, setMessages]);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages]);

  const handleThreadSelect = useCallback(
    async (threadId: string | null) => {
      if (isStreaming) stop();

      if (!threadId) {
        setActiveThreadId(null);
        streamThreadIdRef.current = null;
        setMessages([]);
        startTimeRef.current = Date.now();
        return;
      }

      try {
        const thread = await getChatThread(threadId);
        setActiveThreadId(thread.id);
        streamThreadIdRef.current = thread.id;
        setMessages((thread.messages ?? []) as UIMessage[]);
        startTimeRef.current = Date.now();
      } catch (err) {
        console.error("[ChatPanel] Failed to load thread:", err);
      }
    },
    [setMessages, isStreaming, stop]
  );

  const handleNewThread = useCallback(() => {
    if (isStreaming) stop();
    setActiveThreadId(null);
    streamThreadIdRef.current = null;
    setMessages([]);
    setInputValue("");
    startTimeRef.current = Date.now();
  }, [setMessages, isStreaming, stop]);

  const handleSubmit = useCallback(() => {
    if (!inputValue.trim()) return;
    const text = inputValue;
    setInputValue("");
    streamThreadIdRef.current = activeThreadId;
    startTimeRef.current = startTimeRef.current || Date.now();
    sendMessage({ text });
  }, [inputValue, sendMessage, activeThreadId]);

  const handleSuggestionClick = useCallback(
    (suggestion: string) => {
      setInputValue("");
      streamThreadIdRef.current = activeThreadId;
      startTimeRef.current = Date.now();
      sendMessage({ text: suggestion });
    },
    [sendMessage, activeThreadId]
  );

  return (
    <div className="flex h-full flex-col bg-muted">
      <ChatHeader
        threads={threads}
        activeThreadId={activeThreadId}
        onThreadSelect={handleThreadSelect}
        onNewThread={handleNewThread}
        onClose={onClose}
        selectedProvider={selectedProvider}
        selectedModel={selectedModel}
        onModelChange={handleModelChange}
      />

      <div className="flex-1 overflow-y-auto px-4 py-5">
        {messages.length === 0 ? (
          <ChatEmptyState onSuggestionClick={handleSuggestionClick} />
        ) : (
          <div className="flex flex-col gap-4">
            {messages.map((message, i) => (
              <ChatMessage
                key={message.id ?? i}
                message={message}
                isStreaming={
                  isStreaming && i === messages.length - 1 && message.role === "assistant"
                }
              />
            ))}
            <div ref={messagesEndRef} />
          </div>
        )}
      </div>

      <ChatInput
        value={inputValue}
        onChange={setInputValue}
        onSubmit={handleSubmit}
        onStop={stop}
        isStreaming={isStreaming}
        wordCount={wordCount}
        hasMessages={messages.length > 0}
      />
    </div>
  );
}

"use client"

import { ChevronLeft, ChevronRight, GripVerticalIcon } from "lucide-react"
import * as ResizablePrimitive from "react-resizable-panels"

import { cn } from "@/lib/utils"

function ResizablePanelGroup({
  className,
  ...props
}: ResizablePrimitive.GroupProps) {
  return (
    <ResizablePrimitive.Group
      data-slot="resizable-panel-group"
      className={cn(
        "flex h-full w-full aria-[orientation=vertical]:flex-col",
        className
      )}
      {...props}
    />
  )
}

function ResizablePanel({ ...props }: ResizablePrimitive.PanelProps) {
  return <ResizablePrimitive.Panel data-slot="resizable-panel" {...props} />
}

interface ExtendedHandleProps {
  onCollapseToggle?: () => void
  collapseDirection?: "left" | "right"
  isCollapsed?: boolean
  collapseLabel?: string
}

function ResizableHandle({
  withHandle,
  className,
  onCollapseToggle,
  collapseDirection,
  isCollapsed,
  collapseLabel,
  ...props
}: ResizablePrimitive.SeparatorProps & {
  withHandle?: boolean
} & ExtendedHandleProps) {
  // Determine which chevron to show:
  // - collapseDirection="right" + not collapsed → ChevronRight (collapse right panel)
  // - collapseDirection="right" + collapsed → ChevronLeft (expand right panel)
  // - collapseDirection="left" + not collapsed → ChevronLeft (collapse left panel)
  // - collapseDirection="left" + collapsed → ChevronRight (expand left panel)
  const ChevronIcon =
    collapseDirection === "right"
      ? isCollapsed
        ? ChevronLeft
        : ChevronRight
      : isCollapsed
        ? ChevronRight
        : ChevronLeft

  const actionLabel = isCollapsed ? "Expand" : "Collapse"

  return (
    <ResizablePrimitive.Separator
      data-slot="resizable-handle"
      disabled={isCollapsed}
      className={cn(
        "bg-border focus-visible:ring-ring relative flex w-px shrink-0 self-stretch items-center justify-center after:absolute after:inset-y-0 after:left-1/2 after:w-1 after:-translate-x-1/2 focus-visible:ring-1 focus-visible:ring-offset-1 focus-visible:outline-hidden aria-[orientation=horizontal]:h-px aria-[orientation=horizontal]:w-full aria-[orientation=horizontal]:after:left-0 aria-[orientation=horizontal]:after:h-1 aria-[orientation=horizontal]:after:w-full aria-[orientation=horizontal]:after:translate-x-0 aria-[orientation=horizontal]:after:-translate-y-1/2 [&[aria-orientation=horizontal]>div]:rotate-90",
        onCollapseToggle && "group/handle",
        isCollapsed && "cursor-default",
        className
      )}
      {...props}
    >
      {withHandle && !isCollapsed && (
        <div className="bg-border z-10 flex h-4 w-3 items-center justify-center rounded-xs border">
          <GripVerticalIcon className="size-2.5" />
        </div>
      )}
      {onCollapseToggle && (
        <button
          type="button"
          className={cn(
            "absolute z-20 flex h-6 w-6 items-center justify-center rounded-sm border bg-background shadow-xs opacity-0 transition-opacity duration-150 group-hover/handle:opacity-100 focus-visible:opacity-100 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring",
            withHandle && !isCollapsed && "-translate-y-6"
          )}
          aria-label={`${actionLabel} ${collapseLabel || "panel"}`}
          aria-expanded={!isCollapsed}
          onPointerDown={(e) => {
            e.preventDefault()
            e.stopPropagation()
          }}
          onClick={(e) => {
            e.stopPropagation()
            onCollapseToggle()
          }}
        >
          <ChevronIcon className="h-4 w-4" />
        </button>
      )}
    </ResizablePrimitive.Separator>
  )
}

export { ResizableHandle, ResizablePanel, ResizablePanelGroup }

"use client";

interface MinimapEvent {
  type: "writing" | "ai" | "paste";
  timestamp: string | Date | null;
}

interface TimelineMinimapProps {
  interactions: Array<{ createdAt: string | Date | null }>;
  pasteEvents: Array<{ createdAt: string | Date | null }>;
  sessions: Array<{
    startedAt: string | Date | null;
    endedAt: string | Date | null;
  }>;
}

const COLORS = {
  writing: "bg-emerald-500",
  ai: "bg-violet-500",
  paste: "bg-orange-500",
};

export function TimelineMinimap({ interactions, pasteEvents, sessions }: TimelineMinimapProps) {
  // Build events with timestamps
  const events: MinimapEvent[] = [];

  for (const session of sessions) {
    if (session.startedAt) {
      events.push({ type: "writing", timestamp: session.startedAt });
    }
  }
  for (const interaction of interactions) {
    if (interaction.createdAt) {
      events.push({ type: "ai", timestamp: interaction.createdAt });
    }
  }
  for (const paste of pasteEvents) {
    if (paste.createdAt) {
      events.push({ type: "paste", timestamp: paste.createdAt });
    }
  }

  if (events.length === 0) return null;

  events.sort((a, b) => {
    const ta = a.timestamp ? new Date(a.timestamp).getTime() : 0;
    const tb = b.timestamp ? new Date(b.timestamp).getTime() : 0;
    return ta - tb;
  });

  const minTime = new Date(events[0].timestamp!).getTime();
  const maxTime = new Date(events[events.length - 1].timestamp!).getTime();
  const range = maxTime - minTime || 1;

  // Build segments: each event gets a proportional segment
  const segments = events.map((e) => {
    const time = new Date(e.timestamp!).getTime();
    const position = ((time - minTime) / range) * 100;
    return { type: e.type, position };
  });

  // Convert to percentage-width segments
  const bars: { type: MinimapEvent["type"]; width: number }[] = [];
  for (let i = 0; i < segments.length; i++) {
    const start = segments[i].position;
    const end = i < segments.length - 1 ? segments[i + 1].position : 100;
    bars.push({ type: segments[i].type, width: Math.max(end - start, 1) });
  }

  // Date labels
  const startDate = new Date(events[0].timestamp!).toLocaleDateString("en-US", { month: "short", day: "numeric" });
  const endDate = new Date(events[events.length - 1].timestamp!).toLocaleDateString("en-US", { month: "short", day: "numeric" });

  return (
    <div data-testid="timeline-minimap">
      {/* Bar */}
      <div className="flex h-3 w-full overflow-hidden rounded-full">
        {bars.map((bar, i) => (
          <div
            key={i}
            className={COLORS[bar.type]}
            style={{ width: `${bar.width}%` }}
          />
        ))}
      </div>

      {/* Date labels */}
      <div className="mt-1 flex justify-between text-xs text-muted-foreground">
        <span>{startDate}</span>
        <span>{endDate}</span>
      </div>

      {/* Legend */}
      <div className="mt-2 flex gap-4 text-xs text-muted-foreground">
        <span className="flex items-center gap-1">
          <span className="inline-block h-2 w-2 rounded-full bg-emerald-500" />
          Writing
        </span>
        <span className="flex items-center gap-1">
          <span className="inline-block h-2 w-2 rounded-full bg-violet-500" />
          AI
        </span>
        <span className="flex items-center gap-1">
          <span className="inline-block h-2 w-2 rounded-full bg-orange-500" />
          Paste
        </span>
      </div>
    </div>
  );
}

import { describe, it, expect, afterEach } from "vitest";
import { Editor } from "@tiptap/core";
import StarterKit from "@tiptap/starter-kit";
import { OriginMark } from "./origin-mark";

function createEditor(content?: Record<string, unknown> | string) {
  return new Editor({
    element: document.createElement("div"),
    extensions: [StarterKit, OriginMark],
    content: content ?? { type: "doc", content: [{ type: "paragraph" }] },
  });
}

describe("OriginMark", () => {
  let editor: Editor;

  afterEach(() => {
    editor?.destroy();
  });

  it("should persist through editor JSON serialization/deserialization", () => {
    const docWithMark = {
      type: "doc",
      content: [
        {
          type: "paragraph",
          content: [
            {
              type: "text",
              text: "AI generated text",
              marks: [
                {
                  type: "origin",
                  attrs: {
                    type: "ai",
                    sourceId: "interaction-123",
                    originalLength: 17,
                  },
                },
              ],
            },
          ],
        },
      ],
    };

    editor = createEditor(docWithMark);
    const json = editor.getJSON();

    const textNode = json.content?.[0]?.content?.[0];
    expect(textNode?.marks).toEqual([
      {
        type: "origin",
        attrs: {
          type: "ai",
          sourceId: "interaction-123",
          originalLength: 17,
          originalText: null,
        },
      },
    ]);

    // Re-create editor from serialized JSON to verify round-trip
    const editor2 = createEditor(json);
    const json2 = editor2.getJSON();
    const textNode2 = json2.content?.[0]?.content?.[0];
    expect(textNode2?.marks).toEqual(textNode?.marks);
    editor2.destroy();
  });

  it("should preserve attrs through HTML round-trip parsing", () => {
    editor = createEditor({
      type: "doc",
      content: [
        {
          type: "paragraph",
          content: [
            {
              type: "text",
              text: "pasted text",
              marks: [
                {
                  type: "origin",
                  attrs: {
                    type: "external_paste",
                    sourceId: "paste-123",
                    originalLength: 11,
                    originalText: "pasted text",
                  },
                },
              ],
            },
          ],
        },
      ],
    });

    const html = editor.getHTML();

    const editor2 = createEditor(html);
    const json2 = editor2.getJSON();
    const textNode2 = json2.content?.[0]?.content?.[0];

    expect(textNode2?.marks).toEqual([
      {
        type: "origin",
        attrs: {
          type: "external_paste",
          sourceId: "paste-123",
          originalLength: 11,
          originalText: "pasted text",
        },
      },
    ]);

    editor2.destroy();
  });

  it("should preserve attrs when editor root class is mutated", () => {
    editor = createEditor({
      type: "doc",
      content: [
        {
          type: "paragraph",
          content: [
            {
              type: "text",
              text: "AI generated text",
              marks: [
                {
                  type: "origin",
                  attrs: {
                    type: "ai",
                    sourceId: "interaction-123",
                    originalLength: 17,
                    originalText: "AI generated text",
                  },
                },
              ],
            },
          ],
        },
      ],
    });

    editor.view.dom.classList.add("lens-off");
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    (editor.view as any).domObserver?.flush?.();

    const json = editor.getJSON();
    const textNode = json.content?.[0]?.content?.[0];
    expect(textNode?.marks).toEqual([
      {
        type: "origin",
        attrs: {
          type: "ai",
          sourceId: "interaction-123",
          originalLength: 17,
          originalText: "AI generated text",
        },
      },
    ]);
  });

  it("should apply origin mark with type='ai' and sourceId for AI text insertion", () => {
    editor = createEditor();

    editor
      .chain()
      .focus()
      .insertContent({
        type: "text",
        text: "AI suggestion",
        marks: [
          {
            type: "origin",
            attrs: {
              type: "ai",
              sourceId: "src-abc",
              originalLength: 13,
            },
          },
        ],
      })
      .run();

    const json = editor.getJSON();
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const textNode = json.content?.[0]?.content?.[0] as any;
    expect(textNode?.text).toBe("AI suggestion");
    expect(textNode?.marks?.[0]?.attrs?.type).toBe("ai");
    expect(textNode?.marks?.[0]?.attrs?.sourceId).toBe("src-abc");
    expect(textNode?.marks?.[0]?.attrs?.originalLength).toBe(13);
  });

  it("should treat unmarked text as human (no origin mark present)", () => {
    editor = createEditor({
      type: "doc",
      content: [
        {
          type: "paragraph",
          content: [{ type: "text", text: "Human typed text" }],
        },
      ],
    });

    const json = editor.getJSON();
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const textNode = json.content?.[0]?.content?.[0] as any;
    expect(textNode?.text).toBe("Human typed text");
    expect(textNode?.marks).toBeUndefined();
  });

  it("should render AI text with origin-ai CSS class", () => {
    editor = createEditor({
      type: "doc",
      content: [
        {
          type: "paragraph",
          content: [
            {
              type: "text",
              text: "ai text",
              marks: [
                {
                  type: "origin",
                  attrs: {
                    type: "ai",
                    sourceId: "s1",
                    originalLength: 7,
                  },
                },
              ],
            },
          ],
        },
      ],
    });

    const html = editor.getHTML();
    expect(html).toContain('class="origin-ai"');
  });

  it("should render pasted text with origin-paste CSS class", () => {
    editor = createEditor({
      type: "doc",
      content: [
        {
          type: "paragraph",
          content: [
            {
              type: "text",
              text: "pasted text",
              marks: [
                {
                  type: "origin",
                  attrs: {
                    type: "external_paste",
                    sourceId: "p1",
                    originalLength: 11,
                  },
                },
              ],
            },
          ],
        },
      ],
    });

    const html = editor.getHTML();
    expect(html).toContain('class="origin-paste"');
  });

  it("should render human text without origin CSS class", () => {
    editor = createEditor({
      type: "doc",
      content: [
        {
          type: "paragraph",
          content: [
            {
              type: "text",
              text: "human text",
              marks: [
                {
                  type: "origin",
                  attrs: {
                    type: "human",
                    sourceId: null,
                    originalLength: null,
                  },
                },
              ],
            },
          ],
        },
      ],
    });

    const html = editor.getHTML();
    expect(html).not.toContain("origin-ai");
    expect(html).not.toContain("origin-paste");
  });

  it("should render with data-origin attribute (invisible mark)", () => {
    editor = createEditor({
      type: "doc",
      content: [
        {
          type: "paragraph",
          content: [
            {
              type: "text",
              text: "marked text",
              marks: [
                {
                  type: "origin",
                  attrs: {
                    type: "ai",
                    sourceId: "s1",
                    originalLength: 11,
                  },
                },
              ],
            },
          ],
        },
      ],
    });

    const html = editor.getHTML();
    expect(html).toContain("data-origin");
  });
});

import { Extension } from "@tiptap/core";
import { Plugin, PluginKey } from "@tiptap/pm/state";
import { DOMParser as ProseMirrorDOMParser } from "@tiptap/pm/model";

export interface PasteHandlerOptions {
  documentId: string;
  onExternalPaste?: (
    content: string,
    characterCount: number,
    sourceId: string
  ) => void;
  recentAIResponses?: string[];
  maxRecentAIResponses?: number;
}

export function classifyPaste(
  clipboardText: string,
  recentAIResponses: string[]
): "external" | "ai_internal" {
  return recentAIResponses.some((r) => r === clipboardText)
    ? "ai_internal"
    : "external";
}

function createSourceId(): string {
  if (globalThis.crypto?.randomUUID) {
    return globalThis.crypto.randomUUID();
  }

  // RFC4122-ish fallback for older runtimes.
  return "xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx".replace(/[xy]/g, (char) => {
    const rand = Math.floor(Math.random() * 16);
    const value = char === "x" ? rand : (rand & 0x3) | 0x8;
    return value.toString(16);
  });
}

declare module "@tiptap/core" {
  interface Storage {
    pasteHandler: {
      recentAIResponses: string[];
    };
  }

  interface Commands<ReturnType> {
    pasteHandler: {
      addRecentAIResponse: (text: string) => ReturnType;
      clearRecentAIResponses: () => ReturnType;
    };
  }
}

export const PasteHandler = Extension.create<PasteHandlerOptions>({
  name: "pasteHandler",

  addOptions() {
    return {
      documentId: "",
      onExternalPaste: undefined,
      recentAIResponses: [],
      maxRecentAIResponses: 10,
    };
  },

  addStorage() {
    return {
      recentAIResponses: [] as string[],
    };
  },

  onCreate() {
    const initial = this.options.recentAIResponses ?? [];
    const max = this.options.maxRecentAIResponses ?? 10;

    if (initial.length > 0) {
      this.storage.recentAIResponses = [...initial].slice(0, max);
    }
  },

  addCommands() {
    return {
      addRecentAIResponse:
        (text: string) =>
        () => {
          const trimmed = text.trim();
          if (!trimmed) return false;

          const max = this.options.maxRecentAIResponses ?? 10;
          const next = [
            trimmed,
            ...this.storage.recentAIResponses.filter((r: string) => r !== trimmed),
          ];
          this.storage.recentAIResponses = next.slice(0, max);
          return true;
        },

      clearRecentAIResponses:
        () =>
        () => {
          this.storage.recentAIResponses = [];
          return true;
        },
    };
  },

  addProseMirrorPlugins() {
    const { onExternalPaste } = this.options;
    const storage = this.storage;

    return [
      new Plugin({
        key: new PluginKey("pasteHandler"),
        props: {
          handlePaste(view, event, slice) {
            const clipboardText =
              event.clipboardData?.getData("text/plain") ??
              slice.content.textBetween(0, slice.content.size, "\n\n");
            if (!clipboardText) return false;

            const { schema } = view.state;
            const originMarkType = schema.marks.origin;
            if (!originMarkType) return false;

            const classification = classifyPaste(
              clipboardText,
              storage.recentAIResponses
            );

            const originType =
              classification === "ai_internal" ? "ai" : "external_paste";
            const sourceId = createSourceId();
            const originMark = originMarkType.create({
              type: originType,
              sourceId,
              originalLength: clipboardText.length,
            });

            const { from, to } = view.state.selection;

            // Try to parse HTML to preserve formatting (headings, bold, etc.)
            const clipboardHtml =
              event.clipboardData?.getData("text/html");
            let parsedSlice = slice;
            if (clipboardHtml) {
              const wrapper = document.createElement("div");
              wrapper.innerHTML = clipboardHtml;
              parsedSlice = ProseMirrorDOMParser.fromSchema(schema).parseSlice(
                wrapper
              );
            }

            if (parsedSlice && parsedSlice.content.childCount > 0) {
              // Insert the parsed rich content, then apply origin mark to the range
              const tr = view.state.tr.replaceRange(from, to, parsedSlice);
              const insertEnd = tr.mapping.map(to);
              tr.addMark(from, insertEnd, originMark);
              view.dispatch(tr);
            } else {
              // Fallback: insert plain text with origin mark
              const textNode = schema.text(clipboardText, [originMark]);
              const tr = view.state.tr.replaceWith(from, to, textNode);
              view.dispatch(tr);
            }

            if (classification !== "ai_internal") {
              onExternalPaste?.(clipboardText, clipboardText.length, sourceId);
            }

            return true;
          },
        },
      }),
    ];
  },
});

import { auth } from "@/auth";
import { db } from "@/lib/db";
import { documents, users } from "@/lib/db/schema";
import { eq, and, isNull } from "drizzle-orm";

export async function requireAuth() {
  const session = await auth();

  if (!session?.user?.id) {
    throw new Error("Unauthorized");
  }

  const [existingUser] = await db
    .select({
      id: users.id,
      email: users.email,
      name: users.name,
      image: users.image,
    })
    .from(users)
    .where(eq(users.id, session.user.id));

  if (existingUser) {
    return {
      ...session.user,
      id: existingUser.id,
      email: existingUser.email ?? session.user.email ?? null,
      name: existingUser.name ?? session.user.name ?? null,
      image: existingUser.image ?? session.user.image ?? null,
    };
  }

  if (!session.user.email) {
    throw new Error("Unauthorized");
  }

  const [existingUserByEmail] = await db
    .select({
      id: users.id,
      email: users.email,
      name: users.name,
      image: users.image,
    })
    .from(users)
    .where(eq(users.email, session.user.email));

  if (existingUserByEmail) {
    return {
      ...session.user,
      id: existingUserByEmail.id,
      email: existingUserByEmail.email ?? session.user.email,
      name: existingUserByEmail.name ?? session.user.name ?? null,
      image: existingUserByEmail.image ?? session.user.image ?? null,
    };
  }

  throw new Error("Unauthorized");
}

export async function requireDocumentOwner(documentId: string) {
  const user = await requireAuth();

  const [document] = await db
    .select()
    .from(documents)
    .where(
      and(eq(documents.id, documentId), isNull(documents.deletedAt))
    );

  if (!document) {
    throw new Error("Not found");
  }

  if (document.userId !== user.id) {
    throw new Error("Forbidden");
  }

  return { user, document };
}

interface TipTapMark {
  type: string;
  attrs?: Record<string, unknown>;
}

interface TipTapNode {
  type?: string;
  text?: string;
  content?: TipTapNode[];
  marks?: TipTapMark[];
}

interface BadgeStats {
  ai_percentage: number;
  external_paste_percentage: number;
  total_characters: number;
}

interface AiInteractionLike {
  action?: string | null;
  response?: string | null;
}

/** Count characters as Unicode code points, not UTF-16 code units. */
function countChars(text: string): number {
  return Array.from(text).length;
}

function walkTextNodes(
  node: TipTapNode,
  callback: (text: string, marks?: TipTapMark[]) => void
) {
  if (node.text != null) {
    callback(node.text, node.marks);
    return;
  }

  if (node.content) {
    for (const child of node.content) {
      walkTextNodes(child, callback);
    }
  }
}

/**
 * Compute Levenshtein edit distance between two strings.
 * Operates on Unicode code points (not UTF-16 code units) for correct
 * handling of emoji and other characters outside the Basic Multilingual Plane.
 */
export function editDistance(a: string, b: string): number {
  // Spread to get code points instead of UTF-16 code units
  const aChars = [...a];
  const bChars = [...b];
  const m = aChars.length;
  const n = bChars.length;
  if (m === 0) return n;
  if (n === 0) return m;
  if (a === b) return 0;

  // Two-row DP (O(n) space)
  let prev = Array.from({ length: n + 1 }, (_, i) => i);
  let curr = new Array<number>(n + 1);

  for (let i = 1; i <= m; i++) {
    curr[0] = i;
    for (let j = 1; j <= n; j++) {
      const cost = aChars[i - 1] === bChars[j - 1] ? 0 : 1;
      curr[j] = Math.min(prev[j] + 1, curr[j - 1] + 1, prev[j - 1] + cost);
    }
    [prev, curr] = [curr, prev];
  }

  return prev[n];
}

const MIN_RESPONSE_MATCH_CHARS = 20;

function findNonOverlappingMatch(
  text: string,
  pattern: string,
  occupied: boolean[]
): number {
  let fromIndex = 0;
  const maxStart = text.length - pattern.length;
  while (fromIndex <= maxStart) {
    const idx = text.indexOf(pattern, fromIndex);
    if (idx === -1) return -1;

    let overlaps = false;
    for (let i = idx; i < idx + pattern.length; i++) {
      if (occupied[i]) {
        overlaps = true;
        break;
      }
    }

    if (!overlaps) return idx;
    fromIndex = idx + 1;
  }

  return -1;
}

/**
 * Fallback estimator for legacy snapshots that have missing/stripped origin attrs.
 * Counts accepted AI responses that are still present verbatim in final text.
 */
export function estimateRetainedAiCharactersFromAcceptedResponses(
  documentText: string,
  interactions: AiInteractionLike[]
): number {
  if (!documentText || interactions.length === 0) return 0;

  const acceptedResponses = interactions
    .filter(
      (interaction) =>
        interaction.action === "accepted" &&
        typeof interaction.response === "string"
    )
    .map((interaction) => interaction.response?.trim() ?? "")
    .filter((response) => countChars(response) >= MIN_RESPONSE_MATCH_CHARS)
    .sort((a, b) => countChars(b) - countChars(a));

  if (acceptedResponses.length === 0) return 0;

  const occupied = new Array(documentText.length).fill(false);
  let retainedChars = 0;

  for (const response of acceptedResponses) {
    const matchStart = findNonOverlappingMatch(documentText, response, occupied);
    if (matchStart === -1) continue;

    for (let i = matchStart; i < matchStart + response.length; i++) {
      occupied[i] = true;
    }
    retainedChars += countChars(response);
  }

  return retainedChars;
}

export function calculateMetrics(doc: TipTapNode): BadgeStats {
  let aiChars = 0;
  let humanChars = 0;
  let externalPasteChars = 0;

  walkTextNodes(doc, (text, marks) => {
    const originMark = marks?.find((m) => m.type === "origin");
    const length = countChars(text);

    if (!originMark || originMark.attrs?.type === "human") {
      humanChars += length;
    } else if (originMark.attrs?.type === "ai") {
      // Check modification threshold using edit distance
      const originalLength = originMark.attrs?.originalLength as
        | number
        | null;
      const originalText = originMark.attrs?.originalText as string | null;

      if (originalText != null) {
        // Use character-level edit distance for accurate comparison
        const distance = editDistance(originalText, text);
        const maxLen = Math.max(countChars(originalText), length);
        if (maxLen > 0 && distance / maxLen > 0.2) {
          // Modified by >20% edit distance — reclassify as human
          humanChars += length;
        } else {
          aiChars += length;
        }
      } else if (
        originalLength != null &&
        originalLength > 0 &&
        Math.abs(length - originalLength) / Math.max(originalLength, length) > 0.2
      ) {
        // Fallback: length-based check for marks without originalText
        // Uses Math.max(originalLength, length) for consistent normalization
        humanChars += length;
      } else {
        aiChars += length;
      }
    } else if (originMark.attrs?.type === "external_paste") {
      externalPasteChars += length;
    } else {
      humanChars += length;
    }
  });

  const total = aiChars + humanChars + externalPasteChars;
  // Use Math.floor to prevent ai% + external% from exceeding 100%
  const aiPct = total > 0 ? Math.floor((aiChars / total) * 100) : 0;
  const externalPct = total > 0 ? Math.floor((externalPasteChars / total) * 100) : 0;
  return {
    ai_percentage: aiPct,
    external_paste_percentage: externalPct,
    total_characters: total,
  };
}

interface RawEvent {
  type: "ai_interaction" | "paste" | "session_start" | "session_end" | "revision";
  timestamp: string | Date | null;
  data: Record<string, unknown>;
}

export interface DayGroup {
  date: string; // YYYY-MM-DD
  label: string; // "Jan 15, 2025"
  sessions: SessionGroup[];
}

export interface SessionGroup {
  startTime: string | null;
  endTime: string | null;
  events: TimelineEvent[];
}

export interface TimelineEvent {
  type: "ai_interaction" | "paste" | "revision";
  timestamp: string | Date | null;
  data: Record<string, unknown>;
}

export interface RevisionCluster {
  count: number;
  startTime: string | Date | null;
  endTime: string | Date | null;
  durationMinutes: number;
}

function toDateKey(ts: string | Date | null): string {
  if (!ts) return "unknown";
  const d = new Date(ts);
  return d.toISOString().split("T")[0];
}

function formatDateLabel(dateKey: string): string {
  if (dateKey === "unknown") return "Unknown Date";
  const d = new Date(dateKey + "T00:00:00");
  return d.toLocaleDateString("en-US", { month: "short", day: "numeric", year: "numeric" });
}

export function groupEventsByDay(events: RawEvent[]): DayGroup[] {
  const dayMap = new Map<string, RawEvent[]>();

  for (const event of events) {
    const key = toDateKey(event.timestamp);
    if (!dayMap.has(key)) dayMap.set(key, []);
    dayMap.get(key)!.push(event);
  }

  const days: DayGroup[] = [];
  const sortedKeys = [...dayMap.keys()].sort();

  for (const key of sortedKeys) {
    const dayEvents = dayMap.get(key)!;
    days.push({
      date: key,
      label: formatDateLabel(key),
      sessions: groupIntoSessions(dayEvents),
    });
  }

  return days;
}

function groupIntoSessions(events: RawEvent[]): SessionGroup[] {
  // Find session boundaries
  const sessionStarts = events.filter((e) => e.type === "session_start");
  const nonSessionEvents = events.filter(
    (e) => e.type !== "session_start" && e.type !== "session_end"
  );

  if (sessionStarts.length === 0) {
    // No sessions, put all events in a single group
    return [{
      startTime: nonSessionEvents[0]?.timestamp?.toString() ?? null,
      endTime: nonSessionEvents[nonSessionEvents.length - 1]?.timestamp?.toString() ?? null,
      events: nonSessionEvents.map((e) => ({
        type: e.type as TimelineEvent["type"],
        timestamp: e.timestamp,
        data: e.data,
      })),
    }];
  }

  // Group events by session
  const sessions: SessionGroup[] = [];
  const sorted = [...events].sort((a, b) => {
    const ta = a.timestamp ? new Date(a.timestamp).getTime() : 0;
    const tb = b.timestamp ? new Date(b.timestamp).getTime() : 0;
    return ta - tb;
  });

  let currentSession: SessionGroup | null = null;

  for (const event of sorted) {
    if (event.type === "session_start") {
      if (currentSession) sessions.push(currentSession);
      currentSession = {
        startTime: event.timestamp?.toString() ?? null,
        endTime: null,
        events: [],
      };
    } else if (event.type === "session_end") {
      if (currentSession) {
        currentSession.endTime = event.timestamp?.toString() ?? null;
        sessions.push(currentSession);
        currentSession = null;
      }
    } else {
      if (!currentSession) {
        currentSession = {
          startTime: event.timestamp?.toString() ?? null,
          endTime: null,
          events: [],
        };
      }
      currentSession.events.push({
        type: event.type as TimelineEvent["type"],
        timestamp: event.timestamp,
        data: event.data,
      });
    }
  }

  if (currentSession) sessions.push(currentSession);

  return sessions;
}

export function clusterRevisions(events: TimelineEvent[]): (TimelineEvent | RevisionCluster)[] {
  const result: (TimelineEvent | RevisionCluster)[] = [];
  let revisionBuffer: TimelineEvent[] = [];

  const flushRevisions = () => {
    if (revisionBuffer.length === 0) return;
    if (revisionBuffer.length <= 2) {
      result.push(...revisionBuffer);
    } else {
      const first = revisionBuffer[0].timestamp;
      const last = revisionBuffer[revisionBuffer.length - 1].timestamp;
      const startMs = first ? new Date(first).getTime() : 0;
      const endMs = last ? new Date(last).getTime() : 0;
      result.push({
        count: revisionBuffer.length,
        startTime: first,
        endTime: last,
        durationMinutes: Math.round((endMs - startMs) / 60000),
      });
    }
    revisionBuffer = [];
  };

  for (const event of events) {
    if (event.type === "revision") {
      revisionBuffer.push(event);
    } else {
      flushRevisions();
      result.push(event);
    }
  }
  flushRevisions();

  return result;
}

export function getEventCounts(events: RawEvent[]): Record<string, number> {
  const counts: Record<string, number> = {
    ai_interaction: 0,
    paste: 0,
    revision: 0,
  };

  for (const event of events) {
    if (event.type in counts) {
      counts[event.type]++;
    }
  }

  return counts;
}
